import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { ShoppingBag, LogIn, ChevronRight } from 'lucide-react';
import { useThemeColor } from '@/hooks/use-theme-color';
import { useDbQuery } from '@/hooks/db-hooks';

export default function Home() {
  useThemeColor();
  const navigate = useNavigate();
  const storeSettingsList = useDbQuery<any>('storeSettings') ?? [];
  const storeSettings = storeSettingsList[0] || null;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-zinc-950 text-slate-100 relative overflow-hidden px-6">
      {/* Background Decor */}
      <div className="absolute inset-0 bg-gradient-to-br from-zinc-950 via-zinc-900 to-zinc-950" />
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full bg-primary/10 blur-[120px] mix-blend-screen" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] rounded-full bg-orange-600/5 blur-[120px] mix-blend-screen" />

      <div className="relative z-10 w-full max-w-md flex flex-col items-center text-center">
        {/* Logo */}
        <div className="w-24 h-24 mb-8 bg-white/5 backdrop-blur-md rounded-3xl flex items-center justify-center shadow-2xl border border-white/10 relative group p-2 overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-tr from-primary/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-3xl" />
          <img
            src={storeSettings?.logo || "/icon-192.png"}
            alt={storeSettings?.storeName || "MesenAe Logo"}
            className="w-full h-full object-contain drop-shadow-2xl transition-transform duration-500 group-hover:scale-110"
            onError={(e) => {
              const target = e.currentTarget;
              target.style.display = 'none';
            }}
          />
        </div>

        <h1 className="text-4xl font-black tracking-tight mb-4 text-transparent bg-clip-text bg-gradient-to-r from-white via-slate-100 to-orange-400">
          {storeSettings?.storeName || "MesenAe"}
        </h1>
        <p className="text-sm text-zinc-400 mb-12 font-medium px-4">
          Selamat datang di portal MesenAe. Silakan pilih layanan yang ingin Anda akses.
        </p>

        <div className="w-full space-y-4">
          <Button
            onClick={() => navigate('/order')}
            className="w-full h-14 text-base font-bold rounded-xl bg-primary hover:bg-primary/90 text-primary-foreground shadow-lg shadow-primary/20 hover:shadow-primary/30 flex items-center justify-between px-6"
          >
            <span className="flex items-center gap-3">
              <ShoppingBag className="w-5 h-5" />
              Self Order Customer
            </span>
            <ChevronRight className="w-5 h-5 opacity-70" />
          </Button>

          <Button
            onClick={() => navigate('/login')}
            variant="outline"
            className="w-full h-14 text-base font-bold rounded-xl border-zinc-800 bg-zinc-900/50 hover:bg-zinc-800 text-white flex items-center justify-between px-6"
          >
            <span className="flex items-center gap-3">
              <LogIn className="w-5 h-5" />
              Login Admin & Staf
            </span>
            <ChevronRight className="w-5 h-5 opacity-70" />
          </Button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import { Html5Qrcode, Html5QrcodeSupportedFormats } from 'html5-qrcode';
import { X, Camera, CameraOff, ZapIcon } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { toast } from 'sonner';

interface BarcodeScannerProps {
  open: boolean;
  onClose: () => void;
  onScan: (barcode: string) => void;
}

export default function BarcodeScanner({ open, onClose, onScan }: BarcodeScannerProps) {
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const [hasFlash, setHasFlash] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [scanning, setScanning] = useState(false);
  const [cameras, setCameras] = useState<{ id: string; label: string }[]>([]);
  const [activeCameraIdx, setActiveCameraIdx] = useState(0);
  const scannerId = 'barcode-scanner-view';

  const stopScanner = async () => {
    if (scannerRef.current) {
      try {
        if (scannerRef.current.isScanning) {
          await scannerRef.current.stop();
        }
        scannerRef.current.clear();
      } catch {
        // ignore stop errors
      }
      scannerRef.current = null;
    }
    setScanning(false);
    setHasFlash(false);
    setFlashOn(false);
  };

  const startScanner = async (cameraId?: string) => {
    await stopScanner();

    // Small delay to let DOM settle after stop
    await new Promise(r => setTimeout(r, 150));

    try {
      const scanner = new Html5Qrcode(scannerId, {
        formatsToSupport: [
          Html5QrcodeSupportedFormats.EAN_13,
          Html5QrcodeSupportedFormats.EAN_8,
          Html5QrcodeSupportedFormats.UPC_A,
          Html5QrcodeSupportedFormats.UPC_E,
          Html5QrcodeSupportedFormats.CODE_128,
          Html5QrcodeSupportedFormats.CODE_39,
          Html5QrcodeSupportedFormats.ITF,
          Html5QrcodeSupportedFormats.CODE_93,
          Html5QrcodeSupportedFormats.QR_CODE,
          Html5QrcodeSupportedFormats.DATA_MATRIX,
        ],
        verbose: false,
      });

      scannerRef.current = scanner;

      const cameraConstraint = cameraId
        ? cameraId
        : { facingMode: { ideal: 'environment' } };

      await scanner.start(
        cameraConstraint as Parameters<typeof scanner.start>[0],
        {
          fps: 15,
          qrbox: { width: 260, height: 160 },
          aspectRatio: 1.5,
          disableFlip: false,
        },
        (decodedText) => {
          onScan(decodedText);
          stopScanner();
        },
        () => {}
      );

      setScanning(true);

      // Check torch capability
      try {
        const track = scanner.getRunningTrackCameraCapabilities();
        if (track && 'torchFeature' in track) {
          setHasFlash(true);
        }
      } catch {
        // torch not available
      }
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      if (msg.includes('NotAllowedError') || msg.includes('Permission')) {
        toast.error('Izin kamera ditolak. Mohon izinkan akses kamera di pengaturan browser.');
      } else if (msg.includes('NotFoundError') || msg.includes('Requested device not found')) {
        toast.error('Kamera tidak ditemukan di perangkat ini.');
      } else if (msg.includes('NotReadableError') || msg.includes('Could not start')) {
        toast.error('Kamera sedang digunakan aplikasi lain.');
      } else {
        toast.error('Gagal memulai kamera. Coba izinkan akses kamera.');
      }
      onClose();
    }
  };

  useEffect(() => {
    if (!open) {
      stopScanner();
      return;
    }

    // Enumerate cameras first
    Html5Qrcode.getCameras()
      .then((devices) => {
        if (devices && devices.length > 0) {
          setCameras(devices);
          // Prefer rear camera (environment)
          const rearIdx = devices.findIndex(d =>
            d.label.toLowerCase().includes('back') ||
            d.label.toLowerCase().includes('rear') ||
            d.label.toLowerCase().includes('environment') ||
            d.label.toLowerCase().includes('belakang')
          );
          const idx = rearIdx >= 0 ? rearIdx : 0;
          setActiveCameraIdx(idx);
          startScanner(devices[idx].id);
        } else {
          // No enumerated cameras, try environment facing mode directly
          startScanner();
        }
      })
      .catch(() => {
        // getCameras failed (e.g. permission not yet granted), try directly
        startScanner();
      });

    return () => {
      stopScanner();
    };
  }, [open]);

  const switchCamera = async () => {
    if (cameras.length < 2) return;
    const nextIdx = (activeCameraIdx + 1) % cameras.length;
    setActiveCameraIdx(nextIdx);
    await startScanner(cameras[nextIdx].id);
  };

  const toggleFlash = async () => {
    if (!scannerRef.current) return;
    try {
      const track = scannerRef.current.getRunningTrackCameraCapabilities();
      if (track && 'torchFeature' in track) {
        const torch = (track as unknown as { torchFeature: () => { apply: (on: boolean) => Promise<void> } }).torchFeature();
        await torch.apply(!flashOn);
        setFlashOn(!flashOn);
      }
    } catch {
      toast.error('Flash tidak didukung di perangkat ini');
    }
  };

  const handleClose = async () => {
    await stopScanner();
    onClose();
  };

  return (
    <Dialog open={open} onOpenChange={v => { if (!v) handleClose(); }}>
      <DialogContent className="max-w-[95vw] rounded-xl p-0 overflow-hidden">
        <DialogHeader className="p-4 pb-0">
          <DialogTitle className="flex items-center gap-2">
            <Camera className="w-5 h-5" />
            Scan Barcode
          </DialogTitle>
        </DialogHeader>

        <div className="relative">
          {/* Scanner viewport */}
          <div id={scannerId} className="w-full aspect-[4/3] bg-black" />

          {/* Overlay controls */}
          <div className="absolute top-3 right-3 flex gap-2">
            {hasFlash && (
              <Button
                variant="secondary"
                size="icon"
                className="h-10 w-10 rounded-full shadow-lg bg-black/50 hover:bg-black/70 border-0"
                onClick={toggleFlash}
              >
                <ZapIcon className={`w-5 h-5 ${flashOn ? 'text-yellow-400' : 'text-white'}`} />
              </Button>
            )}
            {cameras.length > 1 && (
              <Button
                variant="secondary"
                size="icon"
                className="h-10 w-10 rounded-full shadow-lg bg-black/50 hover:bg-black/70 border-0"
                onClick={switchCamera}
                title="Ganti kamera"
              >
                <Camera className="w-5 h-5 text-white" />
              </Button>
            )}
          </div>

          {/* Hint text */}
          <div className="absolute bottom-4 left-0 right-0 flex justify-center">
            <div className="bg-black/60 backdrop-blur-sm px-4 py-2 rounded-full">
              <p className="text-white text-xs text-center">
                Arahkan barcode ke dalam kotak scan
              </p>
            </div>
          </div>
        </div>

        <div className="p-4 pt-2">
          <Button variant="outline" className="w-full" onClick={handleClose}>
            <CameraOff className="w-4 h-4 mr-2" />
            Batal
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { Sheet, SheetContent, SheetHeader, SheetTitle } from '@/components/ui/sheet';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { CheckCircle, UtensilsCrossed } from 'lucide-react';
import type { Transaction, TransactionItemRecord } from '@/hooks/db-hooks';
import { useState, useEffect } from 'react';
import { db } from '@/lib/db';
import { mapTransactionItem } from '@/lib/sync';

function ProcessingBillCard({ bill, onComplete }: { bill: Transaction, onComplete: () => void }) {
  const [items, setItems] = useState<TransactionItemRecord[]>([]);
  useEffect(() => {
    if (!bill.id) return;
    db.from('transaction_items').select('*').eq('transaction_id', bill.id).then(({ data }) => {
      if (data) setItems(data.map((r: any) => mapTransactionItem(r)));
    });
  }, [bill.id]);
  return (
    <Card className="border-border shadow-sm mb-3">
      <CardContent className="p-3">
        <div className="flex justify-between items-start mb-2 border-b pb-2">
          <div>
            <Badge variant="outline" className="font-mono text-xs">{bill.receiptNumber}</Badge>
            <div className="text-xs text-muted-foreground mt-1">
              {bill.customerName && <span className="mr-2">👤 {bill.customerName}</span>}
              {bill.tableNumber && <span>🪑 {String(bill.tableNumber) === 'Bawa Pulang' ? 'Take Away' : /^meja\s+/i.test(String(bill.tableNumber)) ? String(bill.tableNumber) : `Meja ${bill.tableNumber}`}</span>}
            </div>
          </div>
          <Badge className="bg-blue-500 hover:bg-blue-600 capitalize">{bill.kitchenStatus || 'diproses'}</Badge>
        </div>
        <div className="space-y-1 mb-3">
          {items.map(item => (
            <div key={item.id} className="text-xs flex justify-between border-b border-border/30 last:border-0 pb-1 last:pb-0">
              <span className="font-medium">{item.quantity}x {item.productName}</span>
            </div>
          ))}
        </div>
        <Button size="sm" className="w-full text-xs gap-2" onClick={onComplete}>
          <CheckCircle className="w-3.5 h-3.5" />
          Selesaikan Pesanan
        </Button>
      </CardContent>
    </Card>
  );
}

export default function ProcessingBillsModal({
  open,
  onOpenChange,
  processingBills,
  onCompleteBill
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  processingBills: Transaction[];
  onCompleteBill: (id: number) => void;
}) {
  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="bottom" className="h-[80vh] rounded-t-2xl max-w-lg md:max-w-xl mx-auto">
        <SheetHeader>
          <SheetTitle className="text-left flex items-center gap-2">
            <UtensilsCrossed className="w-5 h-5" />
            Pesanan Diproses ({processingBills.length})
          </SheetTitle>
        </SheetHeader>
        <div className="mt-4 overflow-y-auto h-[calc(80vh-80px)] pb-20 scrollbar-hide">
          {processingBills.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground text-sm">Tidak ada pesanan yang sedang diproses.</div>
          ) : (
            processingBills.map(b => (
              <ProcessingBillCard
                key={b.id}
                bill={b}
                onComplete={() => onCompleteBill(b.id!)}
              />
            ))
          )}
        </div>
      </SheetContent>
    </Sheet>
  );
}

import { NavLink, useLocation } from "react-router-dom";
import { cn } from "@/lib/utils";
import {
  LayoutDashboard,
  ShoppingCart,
  Package,
  History,
  QrCode,
  UtensilsCrossed,
  FileText,
  Settings,
  ChevronDown,
  Ticket,
  ChevronLeft,
  ChevronRight,
  LogOut,
  ClipboardList,
  Image as ImageIcon
} from "lucide-react";
import { useState, useEffect } from "react";
import { useDbQuery } from '@/hooks/db-hooks';
import { Badge } from "@/components/ui/badge";

interface AppSidebarProps {
  isMobile?: boolean;
}

export default function AppSidebar({ isMobile = false }: AppSidebarProps) {
  const location = useLocation();
  const [isProductsOpen, setIsProductsOpen] = useState(() => {
    const paths = ["/admin/products", "/admin/supplier", "/admin/stock-in", "/admin/stock-out", "/admin/stock-report"];
    return paths.some(p => location.pathname.startsWith(p));
  });
  const [isPromoOpen, setIsPromoOpen] = useState(() => {
    const paths = ["/admin/qr-menu", "/admin/banners", "/admin/vouchers"];
    return paths.some(p => location.pathname.startsWith(p));
  });
  const [isCollapsed, setIsCollapsed] = useState(() => {
    if (isMobile) return false;
    return localStorage.getItem('mesenae_sidebar_collapsed') === 'true';
  });

  useEffect(() => {
    if (!isMobile) {
      localStorage.setItem('mesenae_sidebar_collapsed', String(isCollapsed));
    }
  }, [isCollapsed, isMobile]);

  useEffect(() => {
    const paths = ["/admin/products", "/admin/supplier", "/admin/stock-in", "/admin/stock-out", "/admin/stock-report"];
    if (paths.some(p => location.pathname.startsWith(p))) {
      setIsProductsOpen(true);
    }
  }, [location.pathname]);

  const storeSettingsList = useDbQuery<any>('storeSettings') ?? [];
  const storeSettings = storeSettingsList[0] || null;

  const openBillsCount = (useDbQuery<any>('transactions') || []).filter((t: any) => t.status === 'open').length;
  const processingCount = (useDbQuery<any>('transactions') || []).filter((t: any) => t.kitchenStatus && t.kitchenStatus !== 'diantarkan' && t.kitchenStatus !== 'pending').length;

  const authData = JSON.parse(localStorage.getItem('admin_auth') || '{}');
  const role = authData.role || 'admin';

  // Komponen NavItem dengan warna kontras navy & modern
  const NavItem = ({ to, icon: Icon, label, badge = 0, exact = false }: any) => {
    const isActive = exact 
      ? location.pathname === to || location.pathname === to + '/' 
      : location.pathname.startsWith(to);

    return (
      <NavLink
        to={to}
        title={isCollapsed ? label : undefined}
        className={cn(
          "group relative flex items-center px-3 py-2.5 my-0.5 rounded-lg transition-all duration-200 text-sm font-medium outline-none",
          isCollapsed ? "justify-center" : "gap-3",
          isActive 
            ? "bg-primary text-primary-foreground font-bold shadow-md shadow-primary/20" 
            : "text-slate-400 hover:bg-white/5 hover:text-white"
        )}
      >
        {/* Indikator aktif vertikal di sisi kiri */}
        {isActive && !isCollapsed && (
          <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1.5 h-5 bg-white rounded-r-full shadow-[0_0_8px_rgba(255,255,255,0.6)]" />
        )}

        <Icon className={cn(
          "w-5 h-5 shrink-0 transition-colors", 
          isActive ? "text-primary-foreground text-white" : "text-slate-400 group-hover:text-white"
        )} />

        {!isCollapsed && <span className="flex-1 truncate">{label}</span>}

        {badge > 0 && (
          <Badge 
            variant={isActive ? "default" : "secondary"} 
            className={cn(
              "text-[10px] px-1.5 h-5 justify-center rounded-full flex shrink-0 items-center font-bold", 
              isActive ? "bg-white text-primary shadow-sm border-none" : "bg-white/10 text-slate-300 border-none",
              isCollapsed ? "absolute top-1 right-1 px-1 h-4 min-w-[16px] text-[8px]" : "min-w-[20px]"
            )}
          >
            {badge > 99 ? '99+' : badge}
          </Badge>
        )}
      </NavLink>
    );
  };

  // Label Grup untuk merapikan hierarki
  const NavGroupLabel = ({ children }: { children: React.ReactNode }) => {
    if (isCollapsed) return <div className="h-4" />;
    return (
      <div className="px-3 text-[10px] font-extrabold uppercase tracking-wider text-slate-500 mt-5 mb-1.5 select-none">
        {children}
      </div>
    );
  };

  return (
    <div className={cn(
      "flex flex-col text-slate-200 shadow-xl shadow-slate-950/20 transition-all duration-300 relative z-20 overflow-visible", 
      isMobile 
        ? "h-full w-full m-0 rounded-none border-none bg-gradient-to-b from-[#0a1128] to-[#101f42]" 
        : "h-screen m-0 rounded-none border-r border-white/10 bg-gradient-to-b from-[#0a1128] to-[#101f42]",
      isCollapsed && !isMobile ? "w-[80px]" : "w-64"
    )}>
      {/* Tombol Toggle Sidebar melayang */}
      {!isMobile && (
        <button 
          onClick={() => setIsCollapsed(!isCollapsed)}
          className="absolute -right-3.5 top-8 bg-[#0a1128] border border-white/10 text-slate-400 hover:text-white p-1.5 rounded-full shadow-lg z-30 transition-all hover:scale-110 focus:outline-none"
        >
          {isCollapsed ? <ChevronRight size={14} strokeWidth={3} /> : <ChevronLeft size={14} strokeWidth={3} />}
        </button>
      )}

      {/* Profil Toko / Brand Header */}
      <div className={cn("flex items-center mt-7 mb-5", isCollapsed ? "justify-center" : "gap-3 px-5")}>
        <div className="w-10 h-10 bg-white/5 backdrop-blur-md rounded-lg shrink-0 flex items-center justify-center shadow-lg border border-white/10 p-1 relative overflow-hidden group">
          {storeSettings?.logo ? (
            <img src={storeSettings.logo} alt="Logo" className="w-full h-full object-contain rounded-lg transition-transform group-hover:scale-105" />
          ) : (
            <img src="/icon-192.png" alt="MesenAe Logo" className="w-full h-full object-contain rounded-lg transition-transform group-hover:scale-105" />
          )}
        </div>
        {!isCollapsed && (
          <div className="flex flex-col overflow-hidden">
            <span className="font-extrabold text-base tracking-tight text-white truncate leading-tight">
              {storeSettings?.storeName || 'MesenAe POS'}
            </span>
            <span className="text-[11px] font-bold text-slate-400 truncate mt-0.5">
              {role === 'admin' ? 'Administrator' : 'Staff'}
            </span>
          </div>
        )}
      </div>

      {/* Navigasi Utama */}
      <nav className="flex-1 px-3 space-y-1 overflow-y-auto custom-scrollbar pb-6">

        {/* Grup 1: Ringkasan & Operasional */}
        <NavGroupLabel>Operasional</NavGroupLabel>
        {role === 'admin' && <NavItem to="/admin" exact icon={LayoutDashboard} label="Dashboard" />}
        {role === 'admin' && <NavItem to="/admin/cashier" icon={ShoppingCart} label="Kasir (POS)" />}
        <NavItem to="/admin/active-orders" icon={ClipboardList} label="Pesanan Aktif" badge={openBillsCount} />
        <NavItem to="/admin/kitchen" icon={UtensilsCrossed} label="Dapur" badge={processingCount} />
        <NavItem to="/admin/history" icon={History} label="Riwayat Transaksi" />

        {/* Grup 2: Manajemen */}
        {role === 'admin' && (
          <>
            <NavGroupLabel>Manajemen</NavGroupLabel>

            {/* Menu Dropdown Produk */}
            <div className="mb-0.5">
              <button
                onClick={() => {
                  if (isCollapsed) setIsCollapsed(false);
                  setIsProductsOpen(!isProductsOpen);
                }}
                title={isCollapsed ? "Inventori" : undefined}
                className={cn(
                  "w-full flex items-center px-3 py-2.5 rounded-lg transition-all duration-200 text-sm font-medium outline-none group", 
                  isCollapsed ? "justify-center" : "gap-3",
                  isProductsOpen && !isCollapsed ? "bg-white/5 text-white font-bold" : "text-slate-400 hover:bg-white/5 hover:text-white"
                )}
              >
                <Package className="w-5 h-5 shrink-0 group-hover:text-white transition-colors" />
                {!isCollapsed && (
                  <>
                    <span className="flex-1 text-left truncate">Inventori</span>
                    <ChevronDown className={cn(
                      "w-4 h-4 shrink-0 transition-transform duration-300", 
                      isProductsOpen ? "rotate-180 text-white" : "text-slate-500"
                    )} />
                  </>
                )}
              </button>

              {/* Isi Dropdown */}
              <div className={cn(
                "grid transition-all duration-300 ease-in-out",
                isProductsOpen && !isCollapsed ? "grid-rows-[1fr] opacity-100 mt-1 mb-2" : "grid-rows-[0fr] opacity-0"
              )}>
                <div className="overflow-hidden">
                  <div className="ml-5 space-y-1 border-l border-white/10 pl-3 py-1">
                    {[
                      { to: "/admin/products", label: "Daftar Produk" },
                      { to: "/admin/supplier", label: "Supplier" },
                      { to: "/admin/stock-in", label: "Stok Masuk" },
                      { to: "/admin/stock-out", label: "Stok Keluar" },
                      { to: "/admin/stock-report", label: "Laporan Stok" },
                    ].map((item) => (
                      <NavLink 
                        key={item.to} 
                        to={item.to} 
                        className={({isActive}) => cn(
                          "block py-2 px-3 rounded-lg text-xs font-semibold transition-colors outline-none", 
                          isActive 
                            ? "text-white font-bold bg-primary/20" 
                            : "text-slate-400 hover:text-white hover:bg-white/5"
                        )}
                      >
                        {item.label}
                      </NavLink>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            {/* Menu Dropdown Pemasaran */}
            <div className="mb-0.5">
              <button
                onClick={() => {
                  if (isCollapsed) setIsCollapsed(false);
                  setIsPromoOpen(!isPromoOpen);
                }}
                title={isCollapsed ? "Pemasaran" : undefined}
                className={cn(
