import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { toast } from 'sonner';
import { 
  ArrowDownToLine, 
  Plus, 
  ChevronLeft, 
  Layers, 
  Calendar, 
  User, 
  FileText 
} from 'lucide-react';

import { useDbQuery, dbInsert, dbUpdate } from '@/hooks/db-hooks';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';

export default function StockInPage() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form States
  const [productId, setProductId] = useState('');
  const [supplierId, setSupplierId] = useState('');
  const [quantity, setQuantity] = useState('');
  const [buyPrice, setBuyPrice] = useState('');
  const [notes, setNotes] = useState('');

  // Filter State
  const [filterSupplier, setFilterSupplier] = useState('all');

  // Database Hooks
  const stockIns = useDbQuery<any>('stockIns') || [];
  const products = useDbQuery<any>('products') || [];
  const suppliers = useDbQuery<any>('suppliers') || [];

  // Filter Data
  const filteredStockIns = stockIns.filter((si: any) =>
    filterSupplier === 'all' || si.supplierId === Number(filterSupplier)
  ).sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const getProductName = (pid: number | string) => products.find((p: any) => p.id === pid)?.name ?? 'Produk Tidak Diketahui';
  const getSupplierName = (sid: number | string) => suppliers.find((s: any) => s.id === sid)?.name ?? 'Supplier Tidak Diketahui';

  const openAdd = () => {
    setProductId('');
    setSupplierId('');
    setQuantity('');
    setBuyPrice('');
    setNotes('');
    setDialogOpen(true);
  };

  const handleSave = async () => {
    const qty = Number(quantity);
    const price = Number(buyPrice);

    if (!productId || !supplierId || qty <= 0 || price <= 0) {
      toast.error('Mohon lengkapi semua field dengan benar');
      return;
    }

    const selectedProduct = Number(productId);
    const selectedSupplier = Number(supplierId);
    const product = products.find((p: any) => p.id === selectedProduct);

    if (!product) {
      toast.error('Produk tidak ditemukan');
      return;
    }

    try {
      setIsSubmitting(true);
      const total = qty * price;

      // 1. Catat ke tabel stockIns
      await dbInsert('stockIns', {
        productId: selectedProduct,
        supplierId: selectedSupplier || 0,
        quantity: qty,
        buyPrice: price,
        totalPrice: total,
        date: new Date().toISOString(),
        notes: notes.trim(),
      });

      // 2. Hitung HPP Baru menggunakan Average Cost (Weighted Average)
      const oldStock = product.stock || 0;
      const oldHpp = product.hpp || 0;
      const newStock = oldStock + qty;
      const newHpp = ((oldStock * oldHpp) + total) / newStock;

      // 3. Catat riwayat perubahan HPP
      await dbInsert('hppHistory', {
        productId: selectedProduct,
        oldHpp,
        newHpp,
        source: 'stock_in',
        date: new Date().toISOString(),
      });

      // 4. Perbarui data stok dan nilai HPP pada tabel produk
      await dbUpdate('products', selectedProduct, {
        stock: newStock,
        hpp: Math.round(newHpp),
        updatedAt: new Date().toISOString(),
      });

      toast.success(`Stok ${product.name} bertambah ${qty}. HPP diperbarui menjadi Rp ${Math.round(newHpp).toLocaleString('id-ID')}`);
      setDialogOpen(false);
    } catch (error: any) {
      console.error(error);
      toast.error('Gagal menyimpan data stock in: ' + (error.message || error));
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="px-4 pt-3 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">
      {/* Action Header */}
      <div className="flex justify-end items-center gap-4">
        <Button size="sm" onClick={openAdd} className="h-10 rounded-xl gap-2 px-4 shadow-sm font-medium">
          <Plus className="w-4 h-4" /> Tambah Stok
        </Button>
      </div>

      {/* Kontrol & Filter */}
      <div className="flex flex-col gap-2.5">
        <Label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Filter Berdasarkan Supplier</Label>
        <Select value={filterSupplier} onValueChange={setFilterSupplier}>
          <SelectTrigger className="h-11 rounded-xl bg-card border-border/60 shadow-sm">
            <SelectValue placeholder="Pilih Supplier" />
          </SelectTrigger>
          <SelectContent className="rounded-xl">
            <SelectItem value="all">Semua Supplier</SelectItem>
            {suppliers.map((s: any) => (
              <SelectItem key={s.id} value={s.id.toString()}>{s.name}</SelectItem>
            ))}
          </SelectContent>
        </Select>
        <div className="text-xs text-muted-foreground pl-1">
          Menampilkan <span className="font-semibold text-foreground">{filteredStockIns.length}</span> riwayat catatan
        </div>
      </div>

      {/* Daftar Riwayat Stock In */}
      {filteredStockIns.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center bg-card/40 border border-dashed border-border/60 rounded-2xl">
          <div className="bg-muted p-4 rounded-full mb-3">
            <ArrowDownToLine className="w-8 h-8 text-muted-foreground/40" />
          </div>
          <h3 className="text-sm font-medium text-foreground">Belum ada riwayat</h3>
          <p className="text-xs text-muted-foreground max-w-xs mt-1">Seluruh data pemasukan stok barang dari supplier akan terdaftar di sini.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filteredStockIns.map((si: any) => (
            <Card key={si.id} className="border border-border/50 shadow-sm hover:shadow-md hover:border-border/80 transition-all duration-200 rounded-xl overflow-hidden bg-card">
              <CardContent className="p-4">
                <div className="flex items-start justify-between gap-4">
                  <div className="space-y-1 flex-1 min-w-0">
                    <h3 className="text-sm font-bold text-foreground truncate">{getProductName(si.productId)}</h3>
                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                      <User className="w-3 h-3 flex-shrink-0" />
                      <span className="truncate">Supplier: {getSupplierName(si.supplierId)}</span>
                    </div>

                    <div className="flex items-center gap-2 mt-2 pt-1">
                      <span className="text-[11px] font-bold bg-emerald-50 text-emerald-700 dark:bg-emerald-950/40 dark:text-emerald-400 px-2 py-0.5 rounded-md">
                        +{si.quantity} Unit
                      </span>
                      <span className="text-xs text-muted-foreground">
                        @ Rp {si.buyPrice.toLocaleString('id-ID')}
                      </span>
                    </div>

                    {si.notes && (
                      <div className="flex items-start gap-1 mt-2 text-xs text-muted-foreground bg-muted/40 p-2 rounded-lg italic border border-border/30">
                        <FileText className="w-3.5 h-3.5 mt-0.5 text-muted-foreground/60 flex-shrink-0" />
                        <span className="line-clamp-2">"{si.notes}"</span>
                      </div>
                    )}
                  </div>

                  <div className="text-right flex-shrink-0 flex flex-col justify-between h-full min-h-[70px]">
                    <div className="flex items-center justify-end gap-1 text-[11px] text-muted-foreground">
                      <Calendar className="w-3 h-3" />
                      {format(new Date(si.date), 'dd MMM yyyy', { locale: id })}
                    </div>
                    <div className="mt-auto">
                      <p className="text-xs text-muted-foreground font-medium">Total Harga</p>
                      <p className="text-sm font-extrabold text-foreground tracking-tight">
                        Rp {si.totalPrice.toLocaleString('id-ID')}
                      </p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Dialog Form Tambah Stok */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-[92vw] sm:max-w-md rounded-2xl p-5 gap-4">
          <DialogHeader>
            <DialogTitle className="text-lg font-bold">Tambah Stok Masuk</DialogTitle>
            <DialogDescription className="text-xs">
              Masukkan detail pembelian barang untuk menambah stok gudang dan memperbarui acuan nilai HPP.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 mt-1">
            {/* Pilihan Produk */}
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Pilih Produk <span className="text-destructive">*</span></Label>
              <Select value={productId} onValueChange={setProductId}>
                <SelectTrigger className="h-11 rounded-xl bg-background border-border/70">
                  <SelectValue placeholder="Pilih item barang" />
                </SelectTrigger>
                <SelectContent className="rounded-xl">
                  {products.map((p: any) => (
                    <SelectItem key={p.id} value={p.id.toString()}>
                      {p.name} <span className="text-xs text-muted-foreground">(Sisa: {p.stock ?? 0})</span>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Pilihan Supplier */}
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Supplier <span className="text-destructive">*</span></Label>
              <Select value={supplierId} onValueChange={setSupplierId}>
                <SelectTrigger className="h-11 rounded-xl bg-background border-border/70">
                  <SelectValue placeholder="Pilih nama supplier" />
                </SelectTrigger>
                <SelectContent className="rounded-xl">
                  {suppliers.map((s: any) => (
                    <SelectItem key={s.id} value={s.id.toString()}>{s.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Grid Input Kuantitas & Harga */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label className="text-xs font-semibold text-foreground">Jumlah Masuk <span className="text-destructive">*</span></Label>
                <Input 
                  type="number" 
                  min="1"
                  value={quantity} 
                  onChange={e => setQuantity(e.target.value)} 
                  placeholder="Contoh: 50" 
                  className="h-11 rounded-xl bg-background border-border/70" 
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs font-semibold text-foreground">Harga Beli / Unit <span className="text-destructive">*</span></Label>
                <Input 
                  type="number" 
                  min="0"
                  value={buyPrice} 
                  onChange={e => setBuyPrice(e.target.value)} 
                  placeholder="Rp" 
                  className="h-11 rounded-xl bg-background border-border/70" 
                />
              </div>
            </div>

            {/* Preview Akumulasi Angka Total */}
            {Number(quantity) > 0 && Number(buyPrice) > 0 && (
              <div className="bg-emerald-50/50 dark:bg-emerald-950/20 border border-emerald-100 dark:border-emerald-900/30 p-3 rounded-xl flex items-center justify-between text-xs transition-all duration-200">
                <span className="text-muted-foreground font-medium flex items-center gap-1.5">
                  <Layers className="w-3.5 h-3.5 text-emerald-500" /> Total Pengeluaran:
                </span>
                <span className="font-bold text-emerald-600 dark:text-emerald-400 text-sm">
                  Rp {(Number(quantity) * Number(buyPrice)).toLocaleString('id-ID')}
                </span>
              </div>
            )}

            {/* Kolom Catatan Opsional */}
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Catatan Tambahan</Label>
              <Input 
                value={notes} 
                onChange={e => setNotes(e.target.value)} 
                placeholder="No. Invoice / Keterangan (Opsional)" 
                className="h-11 rounded-xl bg-background border-border/70" 
              />
            </div>

            {/* Tombol Simpan */}
            <Button 
              className="w-full h-12 text-sm font-semibold rounded-xl shadow-md transition-all mt-2" 
              onClick={handleSave}
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Menyimpan Data...' : 'Konfirmasi & Simpan Stok'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { toast } from 'sonner';
import { 
  ArrowUpFromLine, 
  Plus, 
  ChevronLeft, 
  AlertTriangle, 
  Calendar, 
  Tag, 
  FileText,
  Boxes
} from 'lucide-react';

import { useDbQuery, dbInsert, dbUpdate } from '@/hooks/db-hooks';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';

const REASONS = ['Rusak', 'Hilang', 'Kadaluarsa', 'Retur ke Supplier', 'Pemakaian Sendiri', 'Lainnya'];

export default function StockOutPage() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form States
  const [productId, setProductId] = useState('');
  const [quantity, setQuantity] = useState('');
  const [reason, setReason] = useState('');
  const [notes, setNotes] = useState('');

  // Database Hooks
  const stockOuts = useDbQuery<any>('stockOuts') || [];
  const products = useDbQuery<any>('products') || [];

  // Mengurutkan riwayat dari yang terbaru
  const sortedStockOuts = [...stockOuts].sort(
    (a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  const getProductName = (pid: number | string) => products.find((p: any) => p.id === pid)?.name ?? 'Produk Tidak Diketahui';
  const selectedProduct = products.find((p: any) => p.id === Number(productId));

  const openAdd = () => {
    setProductId('');
    setQuantity('');
    setReason('');
    setNotes('');
    setDialogOpen(true);
  };

  const handleSave = async () => {
    const qty = Number(quantity);

    if (!productId || qty <= 0 || !reason) {
      toast.error('Mohon lengkapi semua field utama');
      return;
    }

    const product = products.find((p: any) => p.id === Number(productId));
    if (!product) {
      toast.error('Produk tidak ditemukan');
      return;
    }

    if (qty > product.stock) {
      toast.error(`Jumlah pengeluaran (${qty}) melebihi stok yang tersedia (${product.stock})`);
      return;
    }

    try {
      setIsSubmitting(true);

      // 1. Catat transaksi pengurangan stok
      await dbInsert('stockOuts', {
        productId: Number(productId),
        quantity: qty,
        reason,
        date: new Date().toISOString(),
        notes: notes.trim(),
      });

      // 2. Potong jumlah stok produk utama
      await dbUpdate('products', product.id, {
        stock: product.stock - qty,
        updatedAt: new Date().toISOString(),
      });

      toast.success(`Stok ${product.name} berhasil dikurangi sebanyak ${qty}`);
      setDialogOpen(false);
    } catch (error: any) {
      console.error(error);
      toast.error('Gagal memproses penyesuaian stok: ' + (error.message || error));
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="px-4 pt-3 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">
      {/* Action Header */}
      <div className="flex justify-end items-center gap-4">
        <Button size="sm" onClick={openAdd} className="h-10 rounded-xl gap-2 px-4 shadow-sm font-medium bg-destructive hover:bg-destructive/90 text-destructive-foreground">
          <Plus className="w-4 h-4" /> Catat Pengurangan
        </Button>
      </div>

      <div className="text-xs text-muted-foreground pl-1">
        Total log aktivitas penyesuaian: <span className="font-semibold text-foreground">{sortedStockOuts.length}</span> catatan
      </div>

      {/* Render Daftar Riwayat Catatan */}
      {sortedStockOuts.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center bg-card/40 border border-dashed border-border/60 rounded-2xl">
          <div className="bg-muted p-4 rounded-full mb-3">
            <ArrowUpFromLine className="w-8 h-8 text-muted-foreground/40" />
          </div>
          <h3 className="text-sm font-medium text-foreground">Tidak ada riwayat stok keluar</h3>
          <p className="text-xs text-muted-foreground max-w-xs mt-1">Seluruh log pembuangan barang cacat, kadaluarsa, atau barang hilang akan muncul di sini.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {sortedStockOuts.map((so: any) => (
            <Card key={so.id} className="border border-border/50 shadow-sm hover:shadow-md hover:border-border/80 transition-all duration-200 rounded-xl overflow-hidden bg-card">
              <CardContent className="p-4">
                <div className="flex items-start justify-between gap-4">
                  <div className="space-y-1 flex-1 min-w-0">
                    <h3 className="text-sm font-bold text-foreground truncate">{getProductName(so.productId)}</h3>

                    <div className="flex items-center gap-2 mt-2">
                      <span className="text-[11px] font-bold bg-destructive/10 text-destructive dark:bg-destructive/95 dark:text-destructive-foreground px-2 py-0.5 rounded-md">
                        -{so.quantity} Unit
                      </span>
                      <span className="text-xs font-medium text-muted-foreground flex items-center gap-1 bg-muted px-2 py-0.5 rounded-md">
                        <Tag className="w-3 h-3" /> {so.reason}
                      </span>
                    </div>

                    {so.notes && (
                      <div className="flex items-start gap-1 mt-2.5 text-xs text-muted-foreground bg-muted/40 p-2 rounded-lg italic border border-border/30">
                        <FileText className="w-3.5 h-3.5 mt-0.5 text-muted-foreground/60 flex-shrink-0" />
                        <span className="line-clamp-2">"{so.notes}"</span>
                      </div>
                    )}
                  </div>

                  <div className="text-right flex-shrink-0 flex flex-col justify-between items-end h-full">
                    <div className="flex items-center gap-1 text-[11px] text-muted-foreground">
                      <Calendar className="w-3 h-3" />
                      {format(new Date(so.date), 'dd MMM yyyy', { locale: id })}
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Dialog Form Stock Out */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-[92vw] sm:max-w-md rounded-2xl p-5 gap-4">
          <DialogHeader>
            <DialogTitle className="text-lg font-bold flex items-center gap-1.5">
              <ArrowUpFromLine className="w-5 h-5 text-destructive" /> Catat Stok Keluar
            </DialogTitle>
            <DialogDescription className="text-xs">
              Kurangi kuantitas persediaan barang secara manual disertai dengan alasan operasional yang jelas.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 mt-1">
            {/* Input Pemilihan Produk */}
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Pilih Produk <span className="text-destructive">*</span></Label>
              <Select value={productId} onValueChange={setProductId}>
                <SelectTrigger className="h-11 rounded-xl bg-background border-border/70">
                  <SelectValue placeholder="Pilih produk penyesuaian" />
                </SelectTrigger>
                <SelectContent className="rounded-xl">
                  {products.filter((p: any) => p.stock > 0).map((p: any) => (
                    <SelectItem key={p.id} value={p.id.toString()}>
                      {p.name} <span className="text-xs text-muted-foreground">(Stok: {p.stock})</span>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Grid Jumlah & Alasan */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <Label className="text-xs font-semibold text-foreground">Jumlah Keluar <span className="text-destructive">*</span></Label>
                <Input 
                  type="number" 
                  min="1"
                  max={selectedProduct?.stock}
                  value={quantity} 
                  onChange={e => setQuantity(e.target.value)} 
                  placeholder="0" 
                  className="h-11 rounded-xl bg-background border-border/70" 
                />
              </div>

              <div className="space-y-1.5">
                <Label className="text-xs font-semibold text-foreground">Alasan Pengurangan <span className="text-destructive">*</span></Label>
                <Select value={reason} onValueChange={setReason}>
                  <SelectTrigger className="h-11 rounded-xl bg-background border-border/70">
                    <SelectValue placeholder="Pilih alasan" />
                  </SelectTrigger>
                  <SelectContent className="rounded-xl">
                    {REASONS.map(r => (
                      <SelectItem key={r} value={r}>{r}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Estimasi Sisa Persediaan */}
            {selectedProduct && quantity && (
              <div className={`p-3 rounded-xl flex items-center justify-between text-xs transition-all border ${
                (selectedProduct.stock - Number(quantity)) <= 0 
                  ? 'bg-amber-50 dark:bg-amber-950/20 border-amber-200 dark:border-amber-900/30 text-amber-700 dark:text-amber-400' 
                  : 'bg-muted/60 border-border/40 text-muted-foreground'
              }`}>
                <span className="font-medium flex items-center gap-1.5">
                  {(selectedProduct.stock - Number(quantity)) <= 0 ? (
                    <AlertTriangle className="w-3.5 h-3.5 text-amber-500" />
                  ) : (
                    <Boxes className="w-3.5 h-3.5 text-foreground/60" />
                  )}
                  Estimasi Sisa Stok:
                </span>
                <span className="font-bold text-foreground text-sm">
                  {selectedProduct.stock - Number(quantity)} {selectedProduct.unit || 'Unit'}
                </span>
              </div>
            )}

            {/* Kolom Keterangan / Notes */}
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Keterangan Tambahan</Label>
              <Input 
                value={notes} 
                onChange={e => setNotes(e.target.value)} 
                placeholder="Lokasi kejadian / nama pemeriksa (Opsional)" 
                className="h-11 rounded-xl bg-background border-border/70" 
              />
            </div>

            {/* Tombol Eksekusi Submit */}
            <Button 
              variant="destructive"
              className="w-full h-12 text-sm font-semibold rounded-xl shadow-md transition-all mt-2" 
              onClick={handleSave}
              disabled={isSubmitting || (selectedProduct && (selectedProduct.stock - Number(quantity) < 0))}
            >
              {isSubmitting ? 'Memproses Data...' : 'Konfirmasi & Kurangi Stok'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from 'react';
import { 
  Package, 
  ArrowDownToLine, 
  ArrowUpFromLine, 
  TrendingUp, 
  AlertTriangle, 
  Warehouse, 
  BarChart3,
  Layers,
  Activity
} from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Tooltip, CartesianGrid } from 'recharts';
import { format, subDays, startOfDay } from 'date-fns';
import { id } from 'date-fns/locale';

import { useDbQuery } from '@/hooks/db-hooks';

const REASON_LABELS: Record<string, string> = {
  rusak: 'Rusak',
  hilang: 'Hilang',
  retur: 'Retur ke Supplier',
  kadaluarsa: 'Kadaluarsa',
  expired: 'Kadaluarsa',
  'pemakaian sendiri': 'Pemakaian Sendiri',
  lainnya: 'Lainnya',
};

export default function StockReport() {
  const [period, setPeriod] = useState<'7' | '30'>('7');
  const days = Number(period);
  const since = startOfDay(subDays(new Date(), days));

  // Database Hooks
  const products = useDbQuery<any>('products') || [];
  const stockIns = (useDbQuery<any>('stockIns') || []).filter(si => new Date(si.date) >= since);
  const stockOuts = (useDbQuery<any>('stockOuts') || []).filter(so => new Date(so.date) >= since);

  // Perhitungan Ringkasan (Summary)
  const totalStockIn = stockIns.reduce((sum, si) => sum + si.quantity, 0);
  const totalStockInValue = stockIns.reduce((sum, si) => sum + (si.totalPrice || 0), 0);
  const totalStockOut = stockOuts.reduce((sum, so) => sum + so.quantity, 0);
  const currentStock = products.reduce((sum, p) => sum + (p.stock || 0), 0);

  // Kategorisasi Kondisi Stok Produk
  const lowStockProducts = products.filter(p => p.stock > 0 && p.stock <= 5);
  const outOfStockProducts = products.filter(p => p.stock === 0);

  // Pengelompokan Stok Keluar Berdasarkan Alasan
  const stockOutByReason = stockOuts.reduce((acc, so) => {
    const reasonKey = so.reason ? so.reason.trim() : 'Lainnya';
    acc[reasonKey] = (acc[reasonKey] || 0) + so.quantity;
    return acc;
  }, {} as Record<string, number>);

  // Formatter Fungsi Label Alasan Dinamis
  const formatReasonLabel = (rawReason: string) => {
    const normalized = rawReason.toLowerCase();
    return REASON_LABELS[normalized] || rawReason;
  };

  // Penyusunan Data Grafik Bar (Aktivitas Harian)
  const chartData = (() => {
    const map: Record<string, { stockIn: number; stockOut: number }> = {};

    // Inisialisasi runtunan tanggal mundur
    for (let i = days - 1; i >= 0; i--) {
      const dateStr = format(subDays(new Date(), i), 'dd/MM');
      map[dateStr] = { stockIn: 0, stockOut: 0 };
    }

    stockIns.forEach(si => {
      const dateStr = format(new Date(si.date), 'dd/MM');
      if (map[dateStr]) map[dateStr].stockIn += si.quantity;
    });

    stockOuts.forEach(so => {
      const dateStr = format(new Date(so.date), 'dd/MM');
      if (map[dateStr]) map[dateStr].stockOut += so.quantity;
    });

    return Object.entries(map).map(([date, data]) => ({ date, ...data }));
  })();

  const formatRupiah = (value: number) => `Rp ${value.toLocaleString('id-ID')}`;

  return (
    <div className="px-4 pt-6 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">
      {/* Action Header */}
      <div className="flex justify-end">
        {/* Pengatur Periode Waktu */}
        <Tabs value={period} onValueChange={v => setPeriod(v as '7' | '30')} className="w-full sm:w-auto">
          <TabsList className="grid grid-cols-2 w-full sm:w-[200px] rounded-xl bg-muted p-1">
            <TabsTrigger value="7" className="rounded-lg text-xs font-medium py-1.5">7 Hari</TabsTrigger>
            <TabsTrigger value="30" className="rounded-lg text-xs font-medium py-1.5">30 Hari</TabsTrigger>
          </TabsList>
        </Tabs>
      </div>

      {/* Grid Widget Ringkasan Utama */}
      <div className="grid grid-cols-3 gap-3">
        <Card className="border border-border/50 shadow-sm bg-card hover:bg-card/70 transition-colors rounded-xl">
          <CardContent className="p-3.5 text-center flex flex-col items-center justify-center">
            <div className="p-1.5 bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 rounded-lg mb-1.5">
              <ArrowDownToLine className="w-4 h-4" />
            </div>
            <p className="text-xl font-bold tracking-tight text-foreground">{totalStockIn}</p>
            <p className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">Stok Masuk</p>
          </CardContent>
        </Card>

        <Card className="border border-border/50 shadow-sm bg-card hover:bg-card/70 transition-colors rounded-xl">
          <CardContent className="p-3.5 text-center flex flex-col items-center justify-center">
            <div className="p-1.5 bg-rose-500/10 text-rose-600 dark:text-rose-400 rounded-lg mb-1.5">
              <ArrowUpFromLine className="w-4 h-4" />
            </div>
            <p className="text-xl font-bold tracking-tight text-foreground">{totalStockOut}</p>
            <p className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">Stok Keluar</p>
          </CardContent>
        </Card>

        <Card className="border border-border/50 shadow-sm bg-card hover:bg-card/70 transition-colors rounded-xl">
          <CardContent className="p-3.5 text-center flex flex-col items-center justify-center">
            <div className="p-1.5 bg-blue-500/10 text-blue-600 dark:text-blue-400 rounded-lg mb-1.5">
              <Package className="w-4 h-4" />
            </div>
            <p className="text-xl font-bold tracking-tight text-foreground">{currentStock}</p>
            <p className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider">Tersedia</p>
          </CardContent>
        </Card>
      </div>

      {/* Valuasi Nilai Finansial Stok */}
      <Card className="border border-border/50 shadow-sm rounded-xl overflow-hidden bg-card">
        <CardHeader className="pb-3 bg-muted/30">
          <CardTitle className="text-sm font-bold flex items-center gap-2 text-foreground">
            <TrendingUp className="w-4 h-4 text-emerald-500" />
            Nilai Belanja Stok Masuk
          </CardTitle>
          <CardDescription className="text-xs text-muted-foreground">Akumulasi pengeluaran modal pembelian persediaan barang.</CardDescription>
        </CardHeader>
        <CardContent className="pt-4 space-y-3">
          <div className="flex justify-between items-baseline">
            <span className="text-sm text-muted-foreground">Total Nilai Pembelian</span>
            <span className="text-2xl font-black text-emerald-600 dark:text-emerald-400 tracking-tight">{formatRupiah(totalStockInValue)}</span>
          </div>
          <div className="border-t border-border/40 pt-2.5 flex justify-between text-xs text-muted-foreground">
            <span>Estimasi biaya per unit barang</span>
            <span className="font-semibold text-foreground">
              {totalStockIn > 0 ? formatRupiah(Math.round(totalStockInValue / totalStockIn)) : formatRupiah(0)} / unit
            </span>
          </div>
        </CardContent>
      </Card>

      {/* Grafik Batang Pergerakan Logistik */}
      <Card className="border border-border/50 shadow-sm rounded-xl bg-card">
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-bold flex items-center gap-2 text-foreground">
            <BarChart3 className="w-4 h-4 text-primary" />
            Tren Grafik Alur Distribusi
          </CardTitle>
          <CardDescription className="text-xs text-muted-foreground">Perbandingan komparatif volume aktivitas barang harian.</CardDescription>
        </CardHeader>
        <CardContent className="pt-2 pb-4">
          <div className="w-full h-[200px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 10, right: 5, left: -25, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(var(--border), 0.1)" />
                <XAxis dataKey="date" tick={{ fontSize: 10, fill: '#888888' }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fontSize: 10, fill: '#888888' }} axisLine={false} tickLine={false} width={35} />
                <Tooltip 
                  formatter={(value: number, name: string) => [value, name === 'stockIn' ? 'Barang Masuk' : 'Barang Keluar']} 
                  contentStyle={{ fontSize: 12, borderRadius: 12, backgroundColor: 'rgba(255,255,255,0.95)', border: '1px solid #e2e8f0' }}
                  labelStyle={{ fontSize: 11, fontWeight: 'bold', marginBottom: 4 }}
                />
                <Bar dataKey="stockIn" fill="#10b981" radius={[4, 4, 0, 0]} maxBarSize={24} name="stockIn" />
                <Bar dataKey="stockOut" fill="#f43f5e" radius={[4, 4, 0, 0]} maxBarSize={24} name="stockOut" />
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center items-center gap-4 text-[11px] mt-2 font-medium text-muted-foreground">
            <div className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-sm bg-emerald-500" /> Barang Masuk</div>
            <div className="flex items-center gap-1.5"><span className="w-2.5 h-2.5 rounded-sm bg-rose-500" /> Barang Keluar</div>
          </div>
        </CardContent>
      </Card>

      {/* Komposisi Kasus Kerusakan/Kehilangan */}
      {Object.keys(stockOutByReason).length > 0 && (
        <Card className="border border-border/50 shadow-sm rounded-xl bg-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-bold flex items-center gap-2 text-foreground">
              <Activity className="w-4 h-4 text-rose-500" />
              Klasifikasi Penyebab Stok Keluar
            </CardTitle>
          </CardHeader>
          <CardContent className="pt-2 divide-y divide-border/40">
            {Object.entries(stockOutByReason).map(([reason, qty]) => (
              <div key={reason} className="flex items-center justify-between py-2.5 first:pt-0 last:pb-0">
                <span className="text-sm font-medium text-muted-foreground">{formatReasonLabel(reason)}</span>
                <span className="text-sm font-bold text-rose-600 dark:text-rose-400 bg-rose-500/10 px-2.5 py-0.5 rounded-md">
                  {qty} Unit
                </span>
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      {/* Bagian Peringatan: Stok Menipis */}
      {lowStockProducts.length > 0 && (
        <Card className="border border-amber-200 dark:border-amber-900/30 shadow-sm rounded-xl bg-amber-50/40 dark:bg-amber-950/10">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-bold flex items-center gap-2 text-amber-600 dark:text-amber-400">
              <AlertTriangle className="w-4 h-4" />
              Stok Menipis ({lowStockProducts.length} SKU)
            </CardTitle>
            <CardDescription className="text-xs text-amber-700/70 dark:text-amber-400/60">
              Daftar barang dengan sisa persediaan di bawah atau sama dengan 5 unit.
            </CardDescription>
          </CardHeader>
          <CardContent className="pt-2 divide-y divide-amber-200/40 dark:divide-amber-900/20">
            {lowStockProducts.slice(0, 5).map(p => (
              <div key={p.id} className="flex items-center justify-between py-2.5 first:pt-0 last:pb-0">
                <span className="text-sm font-medium text-foreground truncate max-w-[200px] sm:max-w-xs">{p.name}</span>
                <span className="text-xs font-bold text-amber-700 dark:text-amber-400 bg-amber-500/10 px-2 py-0.5 rounded-md">
                  Sisa: {p.stock} {p.unit || 'Unit'}
                </span>
              </div>
            ))}
            {lowStockProducts.length > 5 && (
              <p className="text-[11px] text-amber-600/80 text-center pt-2 font-medium">
                +{lowStockProducts.length - 5} produk menipis lainnya tidak ditampilkan
              </p>
            )}
          </CardContent>
        </Card>
      )}

      {/* Bagian Krisis: Stok Kosong */}
      {outOfStockProducts.length > 0 && (
        <Card className="border border-rose-200 dark:border-rose-900/30 shadow-sm rounded-xl bg-rose-50/40 dark:bg-rose-950/10">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-bold flex items-center gap-2 text-rose-600 dark:text-rose-400">
              <Layers className="w-4 h-4" />
              Stok Habis / Kosong ({outOfStockProducts.length} SKU)
            </CardTitle>
            <CardDescription className="text-xs text-rose-700/70 dark:text-rose-400/60">
              Segera hubungi supplier, item di bawah ini tidak dapat ditransaksikan.
            </CardDescription>
          </CardHeader>
          <CardContent className="pt-2 divide-y divide-rose-200/40 dark:divide-rose-900/20">
            {outOfStockProducts.slice(0, 5).map(p => (
              <div key={p.id} className="flex items-center justify-between py-2.5 first:pt-0 last:pb-0">
                <span className="text-sm font-medium text-foreground truncate max-w-[200px] sm:max-w-xs">{p.name}</span>
                <span className="text-xs font-bold text-rose-600 dark:text-rose-400 bg-rose-500/10 px-2 py-0.5 rounded-md">
                  Kosong
                </span>
              </div>
            ))}
            {outOfStockProducts.length > 5 && (
              <p className="text-[11px] text-rose-600/80 text-center pt-2 font-medium">
                +{outOfStockProducts.length - 5} produk kosong lainnya tidak ditampilkan
              </p>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

