    }

    const data = { 
      name: name.trim(), 
      phone: phone.trim(), 
      address: address.trim(), 
      notes: notes.trim() 
    };

    try {
      setIsSubmitting(true);
      if (editSupplier?.id) {
        await dbUpdate('suppliers', editSupplier.id, data);
        toast.success(`Data supplier "${data.name}" berhasil diperbarui`);
      } else {
        await dbInsert('suppliers', { ...data, createdAt: new Date().toISOString() });
        toast.success(`Supplier "${data.name}" berhasil ditambahkan`);
      }
      setDialogOpen(false);
    } catch (error: any) {
      console.error(error);
      toast.error('Gagal menyimpan data supplier: ' + (error.message || error));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!deleteId) return;

    try {
      await dbDelete('suppliers', deleteId);
      toast.success('Supplier berhasil dihapus dari sistem');
    } catch (error: any) {
      console.error(error);
      toast.error('Gagal menghapus data supplier: ' + (error.message || error));
    } finally {
      setDeleteId(null);
    }
  };

  return (
    <div className="px-4 pt-6 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">
      {/* Action Header */}
      <div className="flex justify-end">
        <Button size="sm" onClick={openAdd} className="h-10 rounded-xl gap-2 px-4 shadow-sm font-medium">
          <Plus className="w-4 h-4" /> Tambah Supplier
        </Button>
      </div>

      {/* Kolom Input Pencarian */}
      <div className="relative">
        <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
        <Input 
          placeholder="Cari nama supplier atau nomor telepon..." 
          value={search} 
          onChange={e => setSearch(e.target.value)} 
          className="pl-10 h-11 rounded-xl bg-background border-border/70 shadow-sm"
        />
      </div>

      <div className="text-xs text-muted-foreground pl-1">
        Menampilkan: <span className="font-semibold text-foreground">{filteredSuppliers.length}</span> dari <span className="font-semibold text-foreground">{suppliers.length}</span> mitra tercatat
      </div>

      {/* Render Daftar Supplier */}
      {filteredSuppliers.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center bg-card/40 border border-dashed border-border/60 rounded-2xl">
          <div className="bg-muted p-4 rounded-full mb-3">
            <Truck className="w-8 h-8 text-muted-foreground/40" />
          </div>
          <h3 className="text-sm font-medium text-foreground">Supplier tidak ditemukan</h3>
          <p className="text-xs text-muted-foreground max-w-xs mt-1">Coba periksa kembali kata kunci atau tambahkan data kemitraan baru.</p>
          {search && (
            <Button variant="outline" size="sm" className="mt-4 rounded-xl" onClick={() => setSearch('')}>
              Reset Pencarian
            </Button>
          )}
        </div>
      ) : (
        <div className="space-y-3">
          {filteredSuppliers.map(s => (
            <Card key={s.id} className="border border-border/50 shadow-sm hover:shadow-md hover:border-border/80 transition-all duration-200 rounded-xl overflow-hidden bg-card">
              <CardContent className="p-4">
                <div className="flex items-start justify-between gap-4">
                  <div className="space-y-1.5 flex-1 min-w-0">
                    <h3 className="text-sm font-bold text-foreground truncate">{s.name}</h3>

                    <div className="space-y-1">
                      {s.phone && (
                        <div className="text-xs text-muted-foreground flex items-center gap-1.5">
                          <Phone className="w-3.5 h-3.5 text-muted-foreground/70" /> 
                          <span>{s.phone}</span>
                        </div>
                      )}
                      {s.address && (
                        <div className="text-xs text-muted-foreground flex items-center gap-1.5">
                          <MapPin className="w-3.5 h-3.5 text-muted-foreground/70 flex-shrink-0" /> 
                          <span className="truncate">{s.address}</span>
                        </div>
                      )}
                    </div>

                    {s.notes && (
                      <div className="flex items-start gap-1.5 mt-2.5 text-xs text-muted-foreground bg-muted/50 p-2 rounded-lg italic border border-border/30">
                        <FileText className="w-3.5 h-3.5 mt-0.5 text-muted-foreground/60 flex-shrink-0" />
                        <span className="line-clamp-2">"{s.notes}"</span>
                      </div>
                    )}
                  </div>

                  {/* Tombol Aksi */}
                  <div className="flex gap-1 flex-shrink-0">
                    <Button variant="ghost" size="icon" className="h-9 w-9 rounded-lg hover:bg-muted" onClick={() => openEdit(s)}>
                      <Edit2 className="w-4 h-4 text-muted-foreground" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-9 w-9 rounded-lg hover:bg-destructive/10 text-destructive" onClick={() => setDeleteId(s.id!)}>
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Modal Form Dialog Add/Edit */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-[92vw] sm:max-w-md rounded-2xl p-5 gap-4">
          <DialogHeader>
            <DialogTitle className="text-lg font-bold flex items-center gap-1.5">
              <NotebookTabs className="w-5 h-5 text-primary" /> {editSupplier ? 'Ubah Profil' : 'Registrasi'} Supplier
            </DialogTitle>
            <DialogDescription className="text-xs">
              Lengkapi informasi kontak dan alamat operasional rekanan vendor untuk mempermudah pemesanan stok (*restock*).
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 mt-1">
            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Nama Perusahaan / Supplier <span className="text-destructive">*</span></Label>
              <Input 
                value={name} 
                onChange={e => setName(e.target.value)} 
                placeholder="Contoh: PT Sumber Jaya Mandiri" 
                className="h-11 rounded-xl bg-background border-border/70"
              />
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Nomor Telepon / WhatsApp</Label>
              <Input 
                value={phone} 
                onChange={e => setPhone(e.target.value)} 
                placeholder="Contoh: 08123456789" 
                className="h-11 rounded-xl bg-background border-border/70" 
                type="tel" 
              />
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Alamat Kantor / Gudang</Label>
              <Input 
                value={address} 
                onChange={e => setAddress(e.target.value)} 
                placeholder="Nama jalan, kota atau komplek ruko" 
                className="h-11 rounded-xl bg-background border-border/70" 
              />
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs font-semibold text-foreground">Catatan Internal</Label>
              <Textarea 
                value={notes} 
                onChange={e => setNotes(e.target.value)} 
                placeholder="Termin pembayaran, nama penanggung jawab (sales), atau spesialisasi produk" 
                rows={3} 
                className="rounded-xl bg-background border-border/70 resize-none"
              />
            </div>

            <Button 
              className="w-full h-12 text-sm font-semibold rounded-xl shadow-md transition-all mt-2" 
              onClick={handleSave} 
              disabled={isSubmitting || !name.trim()}
            >
              {isSubmitting ? 'Menyimpan...' : 'Simpan Data Kontrak'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Confirmation Dialog Delete */}
      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent className="max-w-[90vw] sm:max-w-md rounded-2xl p-5">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-base font-bold">Apakah Anda benar-benar yakin?</AlertDialogTitle>
            <AlertDialogDescription className="text-xs">
              Tindakan ini tidak dapat dibatalkan. Menghapus supplier akan memutuskan relasi data pada laporan pembelian masa mendatang.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="mt-2 gap-2 flex-row justify-end">
            <AlertDialogCancel className="rounded-xl text-xs h-10 mt-0">Batal</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground hover:bg-destructive/90 rounded-xl text-xs h-10">
              Ya, Hapus Permanen
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useDbQuery, dbUpdate, dbDelete } from '@/hooks/db-hooks';
import { type Transaction, type TransactionItemRecord } from '@/hooks/db-hooks';
import { useState, useEffect, useMemo, useCallback } from 'react';
import { format, startOfDay, endOfDay } from 'date-fns';
import { id as localeId } from 'date-fns/locale';
import { ArrowLeft, Search, Receipt as ReceiptIcon, Calendar, ChevronRight, ShoppingBag, CalendarIcon, X, Trash2, ShoppingCart, TrendingUp, Filter, User } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from '@/components/ui/sheet';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Checkbox } from '@/components/ui/checkbox';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarPicker } from '@/components/ui/calendar';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { cn } from '@/lib/utils';
import ReceiptDialog from '@/components/Receipt';
import { toast } from 'sonner';

export default function TransactionHistory() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [search, setSearch] = useState('');
  const [selectedTx, setSelectedTx] = useState<Transaction | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const [receiptOpen, setReceiptOpen] = useState(false);
  const [dateFrom, setDateFrom] = useState<Date | undefined>(undefined);
  const [dateTo, setDateTo] = useState<Date | undefined>(undefined);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [restoreStock, setRestoreStock] = useState(true);
  const [filterStatus, setFilterStatus] = useState<'all' | 'lunas' | 'belum lunas'>('all');

  const transactions = (useDbQuery<any>('transactions') || []).sort((a:any, b:any) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const products = useDbQuery<any>('products') || [];
  const allTxItems = useDbQuery<any>('transactionItems') || [];

  const txItemsMap = useMemo(() => {
    const map: Record<number, TransactionItemRecord[]> = {};
    for (const item of allTxItems) {
      if (!map[item.transactionId]) map[item.transactionId] = [];
      map[item.transactionId].push(item);
    }
    return map;
  }, [allTxItems]);

  const getTxItems = useCallback((txId: number | undefined): TransactionItemRecord[] =>
    txId ? (txItemsMap?.[txId] ?? []) : [], [txItemsMap]);

  const paymentMethods = useDbQuery('paymentMethods');
  const pmMap = useMemo(() => {
    const map = new Map<number, string>();
    paymentMethods?.forEach(pm => map.set(pm.id!, pm.name));
    return map;
  }, [paymentMethods]);

  const storeSettings = useDbQuery<any>('storeSettings')?.[0];

  const txIdParam = searchParams.get('txId');
  useEffect(() => {
    if (txIdParam && transactions) {
      const tx = transactions.find(t => t.id === Number(txIdParam) || t.receiptNumber === txIdParam);
      if (tx) {
        setSelectedTx(tx);
        setDetailOpen(true);
      }
    }
  }, [txIdParam, transactions]);

  const getPaymentName = useCallback((pmId: number) => pmMap.get(pmId) || 'Tunai', [pmMap]);

  const filtered = useMemo(() => {
    return transactions?.filter(tx => {
      if (filterStatus !== 'all' && tx.status !== filterStatus) return false;
      if (dateFrom) {
        const txDate = new Date(tx.date);
        if (txDate < startOfDay(dateFrom)) return false;
      }
      if (dateTo) {
        const txDate = new Date(tx.date);
        if (txDate > endOfDay(dateTo)) return false;
      }
      if (search) {
        const q = search.toLowerCase();
        const items = getTxItems(tx.id);
        return (
          tx.receiptNumber.toLowerCase().includes(q) ||
          items.some(it => it.productName.toLowerCase().includes(q))
        );
      }
      return true;
    }) ?? [];
  }, [transactions, filterStatus, dateFrom, dateTo, search, getTxItems]);

  const grouped = useMemo(() => {
    return filtered.reduce<Record<string, Transaction[]>>((acc, tx) => {
      const key = format(new Date(tx.date), 'yyyy-MM-dd');
      if (!acc[key]) acc[key] = [];
      acc[key].push(tx);
      return acc;
    }, {});
  }, [filtered]);

  const dateKeys = useMemo(() => Object.keys(grouped).sort((a, b) => b.localeCompare(a)), [grouped]);

  const filteredTotal = useMemo(() => filtered.filter(t => t.status !== 'open').reduce((s, t) => s + t.total, 0), [filtered]);
  const hasDateFilter = dateFrom || dateTo;

  const openDetail = (tx: Transaction) => {
    setSelectedTx(tx);
    setDetailOpen(true);
  };

  const openReceipt = () => {
    setDetailOpen(false);
    setTimeout(() => setReceiptOpen(true), 200);
  };

  const clearDateFilter = () => {
    setDateFrom(undefined);
    setDateTo(undefined);
  };

  const handleDeleteTransaction = async () => {
    if (!selectedTx?.id) return;
    try {
      if (restoreStock) {
        const items = getTxItems(selectedTx.id);
        for (const item of items) {
          const product = products.find((p: any) => p.id === item.productId);
          if (product) {
            await dbUpdate('products', item.productId, { stock: product.stock + item.quantity });
          }
        }
      }
      const items = getTxItems(selectedTx.id);
      for(const item of items) {
        if(item.id) await dbDelete('transactionItems', item.id);
      }
      await dbDelete('transactions', selectedTx.id);
      setDeleteDialogOpen(false);
      setDetailOpen(false);
      setSelectedTx(null);
      toast.success('Transaksi berhasil dihapus');
    } catch {
      toast.error('Gagal menghapus transaksi');
    }
  };

  const rp = (n: number) => `Rp ${n.toLocaleString('id-ID')}`;

  return (
    <div className="px-4 pt-3 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">

      {/* Control Panel (Filters & Search) */}
      <div className="bg-card border border-border/50 p-4 sm:p-5 rounded-[2rem] shadow-sm mb-6 space-y-4">

        {/* Search & Status Tabs */}
        <div className="flex flex-col md:flex-row gap-4 justify-between">
          <div className="relative flex-1 max-w-md group">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
            <Input
              placeholder="Cari no. struk atau nama produk..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="pl-10 h-11 rounded-xl bg-background border-border/60 shadow-sm focus-visible:ring-1"
            />
          </div>

          {/* Segmented Control for Status */}
          <div className="flex p-1 bg-muted/40 border border-border/50 rounded-xl w-fit shrink-0">
            {([
              { value: 'all', label: 'Semua' },
              { value: 'belum lunas', label: 'Belum Lunas' },
              { value: 'lunas', label: 'Lunas' },
            ] as const).map(tab => (
              <button
                key={tab.value}
                onClick={() => setFilterStatus(tab.value)}
                className={cn(
                  'px-5 py-2 rounded-lg text-xs font-bold transition-all duration-200 select-none',
                  filterStatus === tab.value 
                    ? 'bg-background text-foreground shadow-sm ring-1 ring-border/50' 
                    : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
                )}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        <div className="h-px bg-border/50 w-full" />

        {/* Date Filters */}
        <div className="flex flex-wrap items-center gap-2.5">
          <div className="flex items-center gap-1.5 text-sm font-bold text-muted-foreground mr-1">
            <Filter className="w-4 h-4" /> Rentang:
          </div>
          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" className={cn("h-10 text-xs font-medium gap-2 rounded-xl border-border/60 bg-background shadow-sm hover:bg-muted", dateFrom && "border-primary/50 text-primary bg-primary/5")}>
                <CalendarIcon className="w-4 h-4" />
                {dateFrom ? format(dateFrom, 'dd MMM yyyy', { locale: localeId }) : 'Tanggal Awal'}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0 rounded-xl" align="start">
              <CalendarPicker mode="single" selected={dateFrom} onSelect={setDateFrom} initialFocus className="p-3" />
            </PopoverContent>
          </Popover>

          <span className="text-muted-foreground/50 font-bold">-</span>

          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" className={cn("h-10 text-xs font-medium gap-2 rounded-xl border-border/60 bg-background shadow-sm hover:bg-muted", dateTo && "border-primary/50 text-primary bg-primary/5")}>
                <CalendarIcon className="w-4 h-4" />
                {dateTo ? format(dateTo, 'dd MMM yyyy', { locale: localeId }) : 'Tanggal Akhir'}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0 rounded-xl" align="start">
              <CalendarPicker mode="single" selected={dateTo} onSelect={setDateTo} initialFocus className="p-3" />
            </PopoverContent>
          </Popover>

          {hasDateFilter && (
            <Button variant="ghost" className="h-10 px-3 text-xs font-bold text-destructive hover:bg-destructive/10 rounded-xl ml-auto sm:ml-0" onClick={clearDateFilter}>
              Reset <X className="w-3.5 h-3.5 ml-1" />
            </Button>
          )}
        </div>
      </div>

      {/* Summary Stats */}
      {filtered.length > 0 && (
        <div className="grid grid-cols-2 gap-4 mb-8">
          <Card className="border border-border/50 shadow-sm bg-gradient-to-br from-card to-muted/20 rounded-[1.5rem]">
            <CardContent className="p-5 flex items-center justify-between">
              <div>
                <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-1">Total Transaksi</p>
                <p className="text-2xl font-black text-foreground">{filtered.length} <span className="text-sm font-semibold text-muted-foreground">Nota</span></p>
              </div>
              <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center">
                <ReceiptIcon className="w-6 h-6 text-primary" />
              </div>
            </CardContent>
          </Card>
          <Card className="border border-border/50 shadow-sm bg-gradient-to-br from-card to-muted/20 rounded-[1.5rem]">
            <CardContent className="p-5 flex items-center justify-between">
              <div>
                <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-1">Total Penjualan</p>
                <p className="text-2xl font-black text-primary tracking-tight">{rp(filteredTotal)}</p>
              </div>
              <div className="w-12 h-12 rounded-full bg-success/10 flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-success" />
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Transaction List Grouped by Date */}
      {dateKeys.length === 0 ? (
        <div className="text-center py-20 bg-card border border-dashed border-border/60 rounded-[2rem]">
          <ShoppingBag className="w-16 h-16 text-muted-foreground/30 mx-auto mb-4" strokeWidth={1.5} />
          <h3 className="text-lg font-extrabold text-foreground mb-1">Pencarian Kosong</h3>
          <p className="text-sm font-medium text-muted-foreground max-w-sm mx-auto">
            {hasDateFilter ? 'Tidak ada transaksi pada rentang tanggal yang dipilih.' : 'Belum ada transaksi di sistem Anda.'}
          </p>
        </div>
      ) : (
        <div className="space-y-8">
          {dateKeys.map(dateKey => (
            <div key={dateKey} className="space-y-3">
              <div className="flex items-center gap-3 px-1">
                <Calendar className="w-4 h-4 text-primary" />
                <h3 className="text-sm font-bold text-foreground tracking-wide">
                  {format(new Date(dateKey), 'EEEE, dd MMMM yyyy', { locale: localeId })}
                </h3>
                <Badge variant="outline" className="text-[10px] font-bold bg-muted/50 border-border/60 text-muted-foreground px-2 py-0.5 rounded-md">
                  {grouped[dateKey].length} TRX
                </Badge>
              </div>

              <div className="grid gap-3">
                {grouped[dateKey].map(tx => (
                  <Card
                    key={tx.id ?? tx.receiptNumber}
                    className="group border border-border/60 shadow-sm bg-card hover:border-primary/40 hover:shadow-md transition-all duration-200 cursor-pointer rounded-2xl active:scale-[0.99] overflow-hidden"
                    onClick={() => openDetail(tx)}
                  >
                    <CardContent className="p-4 flex items-center gap-4">
                      <div className={cn(
                        'w-12 h-12 rounded-xl flex items-center justify-center shrink-0 border transition-colors',
                        tx.status === 'open' 
                          ? 'bg-warning/10 text-warning border-warning/20 group-hover:bg-warning/20' 
                          : 'bg-primary/5 text-primary border-primary/10 group-hover:bg-primary/10'
                      )}>
                        {tx.status === 'open' ? <ShoppingCart className="w-5 h-5" /> : <ReceiptIcon className="w-5 h-5" />}
                      </div>

                      <div className="flex-1 min-w-0 flex flex-col justify-center">
                        <div className="flex items-start justify-between gap-3 mb-1">
                          <div className="flex items-center gap-2 min-w-0">
                            <p className="text-sm font-bold text-foreground font-mono truncate">{tx.receiptNumber}</p>
                            {tx.status === 'open' ? (
                              <Badge className="text-[10px] font-black uppercase tracking-wider px-2 py-0 bg-warning text-warning-foreground hover:bg-warning shadow-sm">Open</Badge>
                            ) : (
                              <Badge className="text-[10px] font-black uppercase tracking-wider px-2 py-0 bg-success text-success-foreground hover:bg-success shadow-sm">Lunas</Badge>
                            )}
                          </div>
                          <p className="text-xs font-semibold text-muted-foreground shrink-0 bg-muted/50 px-2 py-0.5 rounded-md">
                            {format(new Date(tx.date), 'HH:mm')}
                          </p>
                        </div>

                        <div className="flex items-center justify-between mt-1">
                          <p className="text-xs font-medium text-muted-foreground truncate max-w-[60%]">
                            {getTxItems(tx.id).map(it => it.productName).join(', ')}
                          </p>
                          <p className="text-base font-black text-foreground">{rp(tx.total)}</p>
                        </div>

                        {/* Tags */}
                        <div className="flex items-center gap-2 mt-2 flex-wrap">
                          {tx.customerName && <span className="text-[10px] font-bold bg-muted text-muted-foreground px-1.5 py-0.5 rounded flex items-center gap-1"><User className="w-3 h-3"/> {tx.customerName}</span>}
                          {tx.tableNumber && <span className="text-[10px] font-bold bg-muted text-muted-foreground px-1.5 py-0.5 rounded flex items-center gap-1"><ShoppingCart className="w-3 h-3"/> {String(tx.tableNumber) === 'Bawa Pulang' ? 'Take Away' : /^meja\s+/i.test(String(tx.tableNumber)) ? String(tx.tableNumber) : `Meja ${tx.tableNumber}`}</span>}
                        </div>
                      </div>
                      <ChevronRight className="w-5 h-5 text-muted-foreground/40 group-hover:text-primary transition-colors shrink-0" />
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Detail Sheet */}
      <Sheet open={detailOpen} onOpenChange={setDetailOpen}>
        <SheetContent side="bottom" className="h-[85vh] rounded-t-[2rem] max-w-lg md:max-w-xl mx-auto flex flex-col p-0 border-border/60 shadow-2xl">
          <SheetHeader className="shrink-0 px-6 py-5 border-b border-border/50 bg-muted/10">
            <SheetTitle className="text-left font-extrabold flex items-center gap-2">
              <ReceiptIcon className="w-5 h-5 text-primary" /> Detail Transaksi
            </SheetTitle>
          </SheetHeader>

          {selectedTx && (
            <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-6">

              {/* Meta Info */}
              <div className="bg-card border border-border/60 rounded-2xl p-4 space-y-2.5 shadow-sm">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-muted-foreground font-medium">Status</span>
                  <Badge className={cn('font-black uppercase tracking-wider text-[10px]', selectedTx.status === 'open' ? 'bg-warning text-warning-foreground' : 'bg-success text-success-foreground')}>
                    {selectedTx.status === 'open' ? 'Open Bill' : 'Lunas'}
                  </Badge>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-muted-foreground font-medium">No. Struk</span>
                  <span className="font-mono font-bold">{selectedTx.receiptNumber}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-muted-foreground font-medium">Tanggal</span>
                  <span className="font-semibold">{format(new Date(selectedTx.date), 'dd MMM yyyy, HH:mm', { locale: localeId })}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-muted-foreground font-medium">Pembayaran</span>
                  <span className="font-semibold">{selectedTx.status === 'open' ? '-' : getPaymentName(selectedTx.paymentMethodId)}</span>
                </div>
                {selectedTx.customerName && (
                  <div className="flex justify-between items-center text-sm pt-2 border-t border-dashed border-border/60 mt-2">
                    <span className="text-muted-foreground font-medium">Pelanggan</span>
                    <span className="font-bold">👤 {selectedTx.customerName}</span>
                  </div>
                )}
                {selectedTx.tableNumber && (
                  <div className="flex justify-between items-center text-sm">
                    <span className="text-muted-foreground font-medium">Meja</span>
                    <span className="font-bold bg-primary/10 text-primary px-2 py-0.5 rounded-md">{selectedTx.tableNumber}</span>
                  </div>
                )}
                {selectedTx.remarks && (
                  <div className="flex justify-between items-start text-sm">
                    <span className="text-muted-foreground font-medium mt-0.5">Catatan</span>
                    <span className="text-right max-w-[60%] font-medium text-amber-600 bg-amber-50 dark:bg-amber-950/30 px-2 py-1 rounded-md">{selectedTx.remarks}</span>
                  </div>
                )}
              </div>

              {/* Items List */}
              <div>
                <p className="text-sm font-bold text-foreground mb-3 flex items-center gap-2">
                  <ShoppingBag className="w-4 h-4 text-primary" /> Rincian Item
                </p>
                <div className="space-y-3">
                  {getTxItems(selectedTx.id).map((item, i) => (
                    <div key={i} className="flex justify-between items-start bg-card border border-border/50 p-3.5 rounded-xl shadow-sm">
                      <div className="flex-1 min-w-0 pr-4">
                        <p className="text-sm font-bold text-foreground leading-snug">{item.productName}</p>
                        <p className="text-xs font-semibold text-muted-foreground mt-1">
                          {item.quantity} × {rp(item.price)}
                          {item.discountAmount > 0 && <span className="text-destructive ml-1">(Diskon {rp(item.discountAmount)})</span>}
                        </p>
                        {item.notes && (
                          <p className="text-[11px] font-bold text-amber-600 mt-1.5 line-clamp-2">📝 {item.notes}</p>
                        )}
                      </div>
                      <p className="text-sm font-black text-foreground mt-0.5">{rp(item.subtotal)}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Calculation Summary */}
              <div className="bg-muted/30 border border-border/60 rounded-2xl p-5 space-y-3">
                <div className="flex justify-between text-sm font-medium">
                  <span className="text-muted-foreground">Subtotal</span>
                  <span>{rp(selectedTx.subtotal)}</span>
                </div>
                {selectedTx.discountAmount > 0 && (
                  <div className="flex justify-between text-sm font-bold text-destructive">
                    <span>Diskon</span>
                    <span>-{rp(selectedTx.discountAmount)}</span>
                  </div>
                )}

                <div className="my-3 border-t-2 border-dashed border-border/60" />

                <div className="flex justify-between text-lg">
                  <span className="font-extrabold text-foreground">Total Tagihan</span>
                  <span className="font-black text-primary">{rp(selectedTx.total)}</span>
                </div>

                {selectedTx.status !== 'open' ? (
                  <div className="pt-3 mt-3 border-t border-border/50 space-y-1.5">
                    <div className="flex justify-between text-xs font-medium">
                      <span className="text-muted-foreground">Uang Dibayar</span>
                      <span>{rp(selectedTx.paymentAmount)}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                      <span className="text-muted-foreground">Kembalian</span>
                      <span className="text-success font-bold">{rp(selectedTx.change)}</span>
                    </div>
                  </div>
                ) : (
                  <div className="mt-3 bg-warning/10 border border-warning/20 rounded-lg p-2 text-center">
                    <p className="text-xs font-bold text-warning uppercase tracking-wider">Menunggu Pembayaran</p>
                  </div>
                )}
              </div>

              {/* Action Buttons */}
              <div className="space-y-3 pt-2">
                {selectedTx.status === 'open' ? (
                  <Button className="w-full h-12 rounded-xl font-bold shadow-md active:scale-[0.98] transition-all" onClick={() => { setDetailOpen(false); navigate('/admin/cashier'); }}>
                    <ShoppingCart className="w-4 h-4 mr-2" />
                    Lanjutkan Pembayaran di Kasir
                  </Button>
                ) : (
                  <Button className="w-full h-12 rounded-xl font-bold shadow-md active:scale-[0.98] transition-all" onClick={openReceipt}>
                    <ReceiptIcon className="w-4 h-4 mr-2" />
                    Lihat & Cetak Struk Digital
                  </Button>
                )}

                <Button
                  variant="outline"
                  className="w-full h-12 rounded-xl font-bold text-destructive border-destructive/30 hover:bg-destructive/10 hover:text-destructive hover:border-destructive/50 transition-colors"
                  onClick={() => { setRestoreStock(true); setDeleteDialogOpen(true); }}
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  Hapus Transaksi Permanen
                </Button>
              </div>

            </div>
          )}
        </SheetContent>
      </Sheet>

      {/* Receipt Dialog */}
      {selectedTx && (
        <ReceiptDialog
          open={receiptOpen}
          onClose={() => setReceiptOpen(false)}
          transaction={selectedTx}
          items={getTxItems(selectedTx.id)}
          storeSettings={storeSettings}
          paymentMethodName={getPaymentName(selectedTx.paymentMethodId)}
        />
      )}

      {/* Delete Confirmation */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent className="max-w-[400px] rounded-2xl p-6">
          <AlertDialogHeader>
            <div className="w-12 h-12 rounded-full bg-destructive/10 flex items-center justify-center mb-2 mx-auto">
              <Trash2 className="w-6 h-6 text-destructive" />
            </div>
            <AlertDialogTitle className="text-center text-xl font-extrabold">Hapus Transaksi?</AlertDialogTitle>
            <AlertDialogDescription asChild>
              <div className="space-y-4 text-center mt-2">
                <p className="text-sm">Anda akan menghapus transaksi <span className="font-mono font-bold text-foreground">{selectedTx?.receiptNumber}</span> senilai <span className="font-bold text-foreground">Rp {selectedTx?.total.toLocaleString('id-ID')}</span>.</p>
                <div className="flex items-center justify-center gap-2.5 bg-muted/50 p-3 rounded-xl border border-border/50">
                  <Checkbox
                    id="restore-stock"
                    checked={restoreStock}
                    onCheckedChange={(checked) => setRestoreStock(checked === true)}
                    className="data-[state=checked]:bg-primary data-[state=checked]:border-primary"
                  />
                  <label htmlFor="restore-stock" className="text-sm font-semibold cursor-pointer select-none text-foreground">
                    Kembalikan stok produk ke sistem
                  </label>
                </div>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="mt-6 sm:justify-center flex-row gap-3">
            <AlertDialogCancel className="flex-1 mt-0 rounded-xl h-11 font-bold">Batal</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteTransaction} className="flex-1 rounded-xl h-11 font-bold bg-destructive hover:bg-destructive/90 text-white shadow-md shadow-destructive/20">
              Hapus Permanen
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <style dangerouslySetInnerHTML={{__html: `
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background-color: rgba(156, 163, 175, 0.3); border-radius: 20px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background-color: rgba(156, 163, 175, 0.5); }
      `}} />
    </div>
  );
}

import { useDbQuery, dbInsert, dbUpdate, dbDelete } from '@/hooks/db-hooks';
import { type Voucher, type Product } from '@/hooks/db-hooks';
import { useState } from 'react';
import { Plus, Ticket, Edit2, Trash2, Tag, Percent, Banknote, ListFilter, Sparkles } from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Badge } from '@/components/ui/badge';
import { FORMAT_IDR } from '@/lib/utils';
import { Switch } from '@/components/ui/switch';
import { VouchersSkeleton } from '@/admin/components/SkeletonLoaders';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
export default function Vouchers() {

  // --- Voucher States ---
  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<number | null>(null);
  const [editVoucher, setEditVoucher] = useState<Voucher | null>(null);

  const [code, setCode] = useState('');
  const [type, setType] = useState<'percentage' | 'nominal'>('percentage');
  const [value, setValue] = useState('');
  const [isActive, setIsActive] = useState(true);
  const [applicableProductIds, setApplicableProductIds] = useState<number[]>([]);

  // Queries
  const vouchers = useDbQuery<Voucher>('vouchers');
  const products = useDbQuery<Product>('products');

  // Loading state
  if (vouchers === undefined || products === undefined) {
    return <VouchersSkeleton />;
  }

  // --- Voucher Handlers ---
  const openAdd = () => {
    setEditVoucher(null);
    setCode('');
    setType('percentage');
    setValue('');
    setIsActive(true);
    setApplicableProductIds([]);
    setDialogOpen(true);
  };

  const openEdit = (v: Voucher) => {
    setEditVoucher(v);
    setCode(v.code);
    setType(v.type as 'percentage' | 'nominal');
    setValue(v.value.toString());
    setIsActive(v.isActive);
    setApplicableProductIds(v.applicableProductIds || []);
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!code.trim() || !value) return;

    const data = {
      code: code.trim().toUpperCase(),
      type,
      value: Number(value) || 0,
      isActive,
      applicableProductIds,
      validUntil: null,
      updatedAt: new Date().toISOString(),
    };

    try {
      if (editVoucher?.id) {
        await dbUpdate('vouchers', editVoucher.id, data);
        toast.success('Voucher berhasil diperbarui');
      } else {
        await dbInsert('vouchers', { ...data, createdAt: new Date().toISOString() } as Voucher);
        toast.success('Voucher baru berhasil dibuat');
      }
      setDialogOpen(false);
    } catch (err: any) {
      toast.error('Gagal menyimpan voucher: ' + (err.message || err));
    }
  };

  const handleDelete = async () => {
    if (deleteId) {
      try {
        await dbDelete('vouchers', deleteId);
        toast.success('Voucher berhasil dihapus');
      } catch (err: any) {
        toast.error('Gagal menghapus voucher: ' + (err.message || err));
      } finally {
        setDeleteId(null);
      }
    }
  };

  return (
    <div className="px-4 pt-6 pb-24 space-y-6 w-full mx-auto animate-in fade-in duration-300">
      {/* Action Header */}
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold tracking-tight text-foreground">Kelola Voucher</h2>
        <Button onClick={openAdd} className="h-11 px-5 rounded-xl font-bold bg-primary hover:bg-primary/90 text-white shadow-md shadow-primary/20 active:scale-[0.98] transition-all shrink-0">
          <Plus className="w-5 h-5 mr-2" strokeWidth={3} />
          Buat Voucher
        </Button>
      </div>

          {vouchers.length === 0 ? (
            <div className="bg-card border border-dashed border-border/60 rounded-[2rem] p-12 flex flex-col items-center justify-center text-center opacity-80 mt-6">
              <div className="w-20 h-20 bg-primary/10 rounded-full flex items-center justify-center mb-4">
                <Ticket className="w-10 h-10 text-primary/50" strokeWidth={1.5} />
              </div>
              <h3 className="text-lg font-bold text-foreground mb-1">Belum Ada Voucher</h3>
              <p className="text-sm text-muted-foreground max-w-sm">Anda belum membuat kode promo apapun. Mulai buat sekarang untuk memberi kejutan ke pelanggan.</p>
              <Button variant="outline" className="mt-6 rounded-xl border-primary/20 text-primary hover:bg-primary/10 font-bold" onClick={openAdd}>
                <Plus className="w-4 h-4 mr-2" /> Buat Voucher Pertama
              </Button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mt-6">
              {vouchers.map(v => (
                <Card key={v.id} className={cn(
                  "group relative overflow-hidden border-2 shadow-sm hover:shadow-md transition-all duration-300 rounded-2xl flex flex-col bg-card",
                  v.isActive ? "border-primary/20 hover:border-primary/40" : "border-border/50 opacity-70 grayscale-[0.2]"
                )}>

                  {/* Efek Garis Putus-putus Khas Tiket */}
                  <div className="absolute left-[30%] sm:left-[25%] top-0 bottom-0 border-l-2 border-dashed border-border/60 z-10" />
                  <div className="absolute left-[30%] sm:left-[25%] top-[-10px] w-5 h-5 bg-background rounded-full border-b-2 border-border/60 z-10 -translate-x-1/2" />
                  <div className="absolute left-[30%] sm:left-[25%] bottom-[-10px] w-5 h-5 bg-background rounded-full border-t-2 border-border/60 z-10 -translate-x-1/2" />

                  <div className="flex h-full">

                    <div className={cn(
                      "w-[30%] sm:w-[25%] flex flex-col items-center justify-center p-4 relative overflow-hidden",
                      v.isActive ? "bg-gradient-to-br from-primary via-primary/90 to-primary/80 text-primary-foreground shadow-inner" : "bg-muted text-muted-foreground"
                    )}>
                      {v.isActive && (
                        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10 mix-blend-overlay"></div>
                      )}
                      {v.type === 'percentage' ? (
                        <Percent className="w-8 h-8 mb-1 opacity-50" strokeWidth={2} />
                      ) : (
                        <Banknote className="w-8 h-8 mb-1 opacity-50" strokeWidth={2} />
                      )}
                      <h4 className="text-2xl font-black tracking-tighter text-center leading-none">
                        {v.type === 'percentage' ? `${v.value}%` : FORMAT_IDR(v.value).replace('Rp', '')}
                      </h4>
                      <span className="text-[10px] font-bold uppercase tracking-widest mt-1 opacity-70">Diskon</span>
                    </div>

                    {/* Bagian Kanan Tiket (Detail & Aksi) */}
                    <div className="flex-1 p-5 pl-8 flex flex-col relative z-20">
                      <div className="flex justify-between items-start gap-4">
                        <div className="min-w-0">
                          <div className="flex items-center gap-2 mb-1.5">
                            <Badge variant="outline" className={cn(
                              "text-[9px] uppercase tracking-widest font-black px-1.5 py-0 border-none shadow-none",
                              v.isActive ? "bg-green-500/10 text-green-600" : "bg-muted text-muted-foreground"
                            )}>
                              {v.isActive ? 'Aktif' : 'Nonaktif'}
                            </Badge>
                          </div>
                          <h3 className="font-extrabold text-2xl font-mono tracking-widest text-foreground truncate">{v.code}</h3>

                          {v.applicableProductIds && v.applicableProductIds.length > 0 ? (
                            <p className="text-[11px] font-medium text-muted-foreground mt-2 flex items-center gap-1.5">
                              <ListFilter className="w-3.5 h-3.5" /> Berlaku untuk {v.applicableProductIds.length} produk pilihan
                            </p>
                          ) : (
                            <p className="text-[11px] font-medium text-muted-foreground mt-2 flex items-center gap-1.5">
                              <Tag className="w-3.5 h-3.5" /> Berlaku untuk semua produk
                            </p>
                          )}
                        </div>
                      </div>

                      <div className="mt-auto pt-4 flex gap-2 justify-end opacity-100 sm:opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button variant="outline" size="icon" className="h-8 w-8 rounded-lg bg-background hover:bg-primary/10 hover:text-primary border-border/60" onClick={() => openEdit(v)}>
                          <Edit2 className="w-3.5 h-3.5" />
                        </Button>
                        <Button variant="outline" size="icon" className="h-8 w-8 rounded-lg bg-background hover:bg-destructive/10 hover:text-destructive border-border/60" onClick={() => setDeleteId(v.id!)}>
                          <Trash2 className="w-3.5 h-3.5" />
                        </Button>
                      </div>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          )}

      {/* ==========================================
          MODALS & DIALOGS
          ========================================== */}

      {/* Modal Add/Edit Voucher */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-[480px] rounded-[2rem] p-0 overflow-hidden border-border/60 shadow-2xl">
          <DialogHeader className="px-6 py-5 border-b border-border/50 bg-muted/10">
            <DialogTitle className="text-xl font-extrabold flex items-center gap-2">
              <div className="p-1.5 bg-primary/10 rounded-lg text-primary">
                {editVoucher ? <Edit2 className="w-5 h-5" /> : <Ticket className="w-5 h-5" strokeWidth={2.5} />}
              </div>
              {editVoucher ? 'Edit Voucher' : 'Buat Voucher Baru'}
            </DialogTitle>
          </DialogHeader>

          <div className="px-6 py-5 space-y-5">
            <div className="space-y-2 group">
              <Label className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Kode Promo <span className="text-destructive">*</span></Label>
              <div className="relative">
                <Tag className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                <Input 
                  value={code} 
                  onChange={e => setCode(e.target.value.toUpperCase().replace(/\s/g, ''))} 
                  placeholder="Contoh: MERDEKA50" 
                  className="h-12 pl-10 uppercase font-mono font-bold tracking-widest bg-background rounded-xl focus-visible:ring-1 focus-visible:ring-primary" 
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Tipe Diskon <span className="text-destructive">*</span></Label>
                <Select value={type} onValueChange={(val: 'percentage' | 'nominal') => setType(val)}>
                  <SelectTrigger className="h-12 bg-background rounded-xl font-semibold focus:ring-1 focus:ring-primary">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="rounded-xl">
                    <SelectItem value="percentage" className="font-medium">Persentase (%)</SelectItem>
                    <SelectItem value="nominal" className="font-medium">Nominal (Rp)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2 group">
                <Label className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Nilai Diskon <span className="text-destructive">*</span></Label>
                <div className="relative">
                  <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-sm font-bold text-muted-foreground group-focus-within:text-primary transition-colors">
                    {type === 'nominal' ? 'Rp' : '%'}
                  </span>
                  <Input 
                    type="number" 
                    value={value} 
                    onChange={e => setValue(e.target.value)} 
                    placeholder={type === 'percentage' ? "10" : "10000"} 
                    className="h-12 pl-9 bg-background rounded-xl font-mono text-base focus-visible:ring-1 focus-visible:ring-primary" 
                  />
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between items-end mb-1">
                <Label className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Produk Spesifik</Label>
                <span className="text-[10px] font-medium bg-muted px-2 py-0.5 rounded text-muted-foreground">Opsional</span>
              </div>
              <div className="border border-border/60 rounded-xl p-2 max-h-[160px] overflow-y-auto bg-background/50 space-y-1 custom-scrollbar">
                {products.length === 0 ? (
                  <p className="text-xs text-muted-foreground p-3 text-center">Belum ada produk di database.</p>
                ) : (
                  products.map((p) => {
                    const isChecked = applicableProductIds.includes(p.id!);
                    return (
                      <label 
                        key={p.id} 
                        className={cn(
                          "flex items-center gap-3 px-3 py-2 rounded-lg cursor-pointer transition-colors border border-transparent",
                          isChecked ? "bg-primary/5 border-primary/20" : "hover:bg-muted"
                        )}
                      >
                        <input 
                          type="checkbox" 
                          checked={isChecked}
                          onChange={(e) => {
                            if (e.target.checked) setApplicableProductIds([...applicableProductIds, p.id!]);
                            else setApplicableProductIds(applicableProductIds.filter(id => id !== p.id));
                          }}
                          className="w-4 h-4 rounded-md border-muted-foreground/50 text-primary focus:ring-primary"
                        />
                        <span className={cn("text-sm flex-1 truncate select-none", isChecked ? "font-bold text-primary" : "font-medium text-foreground")}>
                          {p.name}
                        </span>
                      </label>
                    );
                  })
                )}
              </div>
              <p className="text-[10px] text-muted-foreground font-medium">Jika tidak ada yang dipilih, voucher berlaku untuk total tagihan seluruh produk.</p>
            </div>

            <div className="flex items-center justify-between p-4 bg-muted/30 border border-border/50 rounded-xl">
              <div>
                <Label htmlFor="active-toggle" className="text-sm font-bold cursor-pointer">Status Aktif</Label>
                <p className="text-[10px] text-muted-foreground font-medium mt-0.5">Voucher dapat digunakan oleh pelanggan saat ini.</p>
              </div>
              <Switch id="active-toggle" checked={isActive} onCheckedChange={setIsActive} className="data-[state=checked]:bg-green-500" />
            </div>
          </div>

          <DialogFooter className="px-6 py-4 border-t border-border/50 bg-muted/10 gap-2 sm:gap-0">
