            <AlertDialogCancel className="flex-1 mt-0 rounded-xl h-11 font-bold">Batal</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="flex-1 rounded-xl h-11 font-bold bg-destructive hover:bg-destructive/90 text-white shadow-md shadow-destructive/20">
              Ya, Hapus
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <style dangerouslySetInnerHTML={{__html: `
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background-color: rgba(156, 163, 175, 0.3); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background-color: rgba(156, 163, 175, 0.5); }
      `}} />
    </div>
  );
}

/**
 * MidtransPaymentModal — Router Utama
 * Membuka modal yang sesuai berdasarkan jenis pembayaran:
 *  - 'qris'      → QrisPaymentModal    (Snap full, langsung ke halaman QRIS)
 *  - 'transfer'  → BankTransferModal   (pilih bank → tampilkan VA)
 *  - 'e-wallet'  → EWalletModal        (pilih dompet → QR / deeplink)
 *  - 'lainnya'   → OtherPaymentModal   (Snap full, semua metode tersedia)
 */
import { QrisPaymentModal } from '@/components/payment/QrisPaymentModal';
import { BankTransferModal } from '@/components/payment/BankTransferModal';
import { EWalletModal } from '@/components/payment/EWalletModal';
import { OtherPaymentModal } from '@/components/payment/OtherPaymentModal';

export type MidtransPaymentType = 'qris' | 'transfer' | 'e-wallet' | 'lainnya';

export interface MidtransPaymentModalProps {
  isOpen: boolean;
  paymentType: MidtransPaymentType | null;
  amount: number;
  customerName?: string;
  orderId?: string;
  onSuccess: () => void;
  onPending: () => void;
  onError: (error?: any) => void;
  onClose: () => void;
}

export function MidtransPaymentModal({
  isOpen,
  paymentType,
  amount,
  customerName,
  orderId,
  onSuccess,
  onClose,
}: MidtransPaymentModalProps) {
  if (!isOpen || !paymentType) return null;

  const sharedProps = { isOpen, amount, customerName, orderId, onSuccess, onClose } as any;

  if (paymentType === 'qris') return <QrisPaymentModal     {...sharedProps} />;
  if (paymentType === 'transfer') return <BankTransferModal    {...sharedProps} />;
  if (paymentType === 'e-wallet') return <EWalletModal         {...sharedProps} />;
  if (paymentType === 'lainnya') return <OtherPaymentModal    {...sharedProps} />;

  return null;
}

import { useRef, useState } from 'react';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import html2canvas from 'html2canvas';
import { Download, Share2, Printer, Loader2, CheckCircle2, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { toast } from 'sonner';
import type { Transaction, StoreSettings, TransactionItemRecord } from '@/hooks/db-hooks';

interface ReceiptProps {
  open: boolean;
  onClose: () => void;
  transaction: Transaction;
  items: TransactionItemRecord[];
  storeSettings: StoreSettings | undefined;
  paymentMethodName: string;
}

export default function Receipt({ open, onClose, transaction, items, storeSettings, paymentMethodName }: ReceiptProps) {
  const receiptRef = useRef<HTMLDivElement>(null);
  const [generating, setGenerating] = useState<boolean>(false);
  const [printing, setPrinting] = useState<boolean>(false);

  if (!transaction) return null;

  const isPaidTx = transaction.status === 'lunas' || transaction.status === 'completed';

  // Normalisasi data untuk menghindari error camelCase vs snake_case
  const txDiscountAmount = transaction.discountAmount ?? (transaction as any).discount_amount ?? 0;
  const txPaymentAmount = transaction.paymentAmount ?? (transaction as any).payment_amount ?? 0;
  const rp = (n: number) => `Rp ${n.toLocaleString('id-ID')}`;

  const captureReceipt = async (): Promise<HTMLCanvasElement | null> => {
    if (!receiptRef.current) return null;
    setGenerating(true);
    try {
      const canvas = await html2canvas(receiptRef.current, {
        backgroundColor: null, // Transparan agar efek shadow/gerigi tetap bagus jika diperlukan
        scale: 3, // Kualitas resolusi lebih tinggi
        useCORS: true,
        logging: false,
      });
      return canvas;
    } catch {
      toast.error('Gagal membuat gambar struk');
      return null;
    } finally {
      setGenerating(false);
    }
  };

  const handleDownload = async () => {
    const canvas = await captureReceipt();
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = `Struk_${transaction.receiptNumber}.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
    toast.success('Struk berhasil diunduh');
  };

  const handleShare = async () => {
    const canvas = await captureReceipt();
    if (!canvas) return;

    try {
      const blob = await new Promise<Blob | null>(resolve => canvas.toBlob(resolve, 'image/png'));
      if (!blob) return;

      if (navigator.share) {
        const file = new File([blob], `Struk_${transaction.receiptNumber}.png`, { type: 'image/png' });
        await navigator.share({
          title: `Struk Pembayaran - ${transaction.receiptNumber}`,
          text: `Terima kasih! Berikut adalah struk pembayaran Anda dari ${storeSettings?.storeName || 'Toko'}.`,
          files: [file],
        });
      } else {
        // Fallback WhatsApp
        const text = encodeURIComponent(
          `*${storeSettings?.storeName || 'Toko'}*\n` +
          `No. Struk: ${transaction.receiptNumber}\n` +
          `Total: ${rp(transaction.total)}\n` +
          `Tanggal: ${format(new Date(transaction.date), 'dd MMM yyyy HH:mm', { locale: id })}`
        );
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err: unknown) {
      if (err instanceof Error && err.name !== 'AbortError') {
        toast.error('Gagal membagikan struk');
      }
    }
  };

  const handleBluetoothPrint = async () => {
    if (!('bluetooth' in navigator)) {
      toast.error('Bluetooth tidak tersedia di browser ini. Gunakan Chrome di Android.');
      return;
    }

    setPrinting(true);
    try {
      toast.info('Mencari printer Bluetooth...');
      // @ts-expect-error Web Bluetooth API is not fully typed
      const device = await navigator.bluetooth.requestDevice({
        filters: [{ services: ['000018f0-0000-1000-8000-00805f9b34fb'] }],
        optionalServices: ['000018f0-0000-1000-8000-00805f9b34fb'],
      });

      const server = await device.gatt.connect();
      const service = await server.getPrimaryService('000018f0-0000-1000-8000-00805f9b34fb');
      const characteristic = await service.getCharacteristic('00002af1-0000-1000-8000-00805f9b34fb');

      // ESC/POS Formatter
      const encoder = new TextEncoder();
      const lines: string[] = [];

      lines.push('\x1B\x40'); // Initialize printer
      lines.push('\x1B\x61\x01'); // Center align
      lines.push('\x1B\x45\x01'); // Bold ON
      lines.push(`${storeSettings?.storeName || 'Toko'}\n`);
      lines.push('\x1B\x45\x00'); // Bold OFF

      if (storeSettings?.address) lines.push(`${storeSettings.address}\n`);
      if (storeSettings?.phone) lines.push(`${storeSettings.phone}\n`);

      lines.push('--------------------------------\n');
      lines.push(`No: ${transaction.receiptNumber}\n`);
      lines.push(`${format(new Date(transaction.date), 'dd/MM/yyyy HH:mm')}\n`);
      if (transaction.customerName) lines.push(`Pelanggan: ${transaction.customerName}\n`);
      lines.push('--------------------------------\n');

      lines.push('\x1B\x61\x00'); // Left align
      for (const item of items) {
        lines.push(`${item.productName}\n`);
        if (item.selectedVariants && item.selectedVariants.length > 0) {
          lines.push(`  + ${item.selectedVariants.map(v => v.optionName).join(', ')}\n`);
        }
        if (item.notes) lines.push(`  Catatan: ${item.notes}\n`);
        lines.push(`  ${item.quantity} x ${rp(item.price)}  ${rp(item.subtotal)}\n`);
      }

      lines.push('--------------------------------\n');
      lines.push(`Subtotal:  ${rp(transaction.subtotal)}\n`);
      if (txDiscountAmount > 0) {
        lines.push(`Diskon:   -${rp(txDiscountAmount)}\n`);
      }

      lines.push('\x1B\x45\x01'); // Bold ON for Total
      lines.push(`TOTAL:     ${rp(transaction.total)}\n`);
      lines.push('\x1B\x45\x00'); // Bold OFF

      const paymentsList = (transaction.payments || []) as any[];
      if (paymentsList.length > 0) {
        lines.push('--------------------------------\n');
        lines.push('Rincian Pembayaran:\n');
        paymentsList.forEach(p => {
          const methodName = p.method_name || p.methodName || 'Pembayaran';
          lines.push(`${methodName}: ${rp(p.amount)}\n`);
        });
      } else {
        lines.push(`Bayar:     ${rp(txPaymentAmount)}\n`);
      }
      lines.push(`Kembali:   ${rp(transaction.change)}\n`);
      lines.push('--------------------------------\n');

      lines.push('\x1B\x61\x01'); // Center align
      lines.push(`${storeSettings?.receiptFooter || 'Terima kasih!'}\n\n\n`);

      const data = encoder.encode(lines.join(''));

      // Send in chunks of 100 bytes to avoid buffer overflow
      for (let i = 0; i < data.length; i += 100) {
        const chunk = data.slice(i, i + 100);
        await characteristic.writeValue(chunk);
      }

      toast.success('Struk berhasil dicetak!');
      await server.disconnect();
    } catch (err: unknown) {
      if (err instanceof Error && err.name !== 'NotFoundError') {
        toast.error('Gagal mencetak. Pastikan printer Bluetooth menyala.');
      }
    } finally {
      setPrinting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="max-w-md w-[95vw] max-h-[90vh] overflow-y-auto rounded-2xl p-6 bg-slate-50 dark:bg-slate-900 border-none">
        <DialogHeader className="mb-2">
          <DialogTitle className="text-center text-slate-800 dark:text-slate-100 flex items-center justify-center gap-2">
            {isPaidTx ? (
              <>
                <CheckCircle2 className="text-emerald-500 w-6 h-6" />
                Pembayaran Berhasil
              </>
            ) : (
              <>
                <Clock className="text-amber-500 w-6 h-6 animate-pulse" />
                Detail Tagihan
              </>
            )}
          </DialogTitle>
        </DialogHeader>

        {/* Kertas Struk dengan Efek Visual */}
        <div className="relative mx-auto bg-white text-slate-800 p-6 shadow-xl w-[300px] mb-6 overflow-hidden" 
             style={{ 
               fontFamily: "'Courier New', Courier, monospace", 
               fontSize: '12px',
               clipPath: 'polygon(0 0, 100% 0, 100% calc(100% - 6px), 98% 100%, 96% calc(100% - 6px), 94% 100%, 92% calc(100% - 6px), 90% 100%, 88% calc(100% - 6px), 86% 100%, 84% calc(100% - 6px), 82% 100%, 80% calc(100% - 6px), 78% 100%, 76% calc(100% - 6px), 74% 100%, 72% calc(100% - 6px), 70% 100%, 68% calc(100% - 6px), 66% 100%, 64% calc(100% - 6px), 62% 100%, 60% calc(100% - 6px), 58% 100%, 56% calc(100% - 6px), 54% 100%, 52% calc(100% - 6px), 50% 100%, 48% calc(100% - 6px), 46% 100%, 44% calc(100% - 6px), 42% 100%, 40% calc(100% - 6px), 38% 100%, 36% calc(100% - 6px), 34% 100%, 32% calc(100% - 6px), 30% 100%, 28% calc(100% - 6px), 26% 100%, 24% calc(100% - 6px), 22% 100%, 20% calc(100% - 6px), 18% 100%, 16% calc(100% - 6px), 14% 100%, 12% calc(100% - 6px), 10% 100%, 8% calc(100% - 6px), 6% 100%, 4% calc(100% - 6px), 2% 100%, 0 calc(100% - 6px))'
             }}>

          <div ref={receiptRef} className="relative z-10 bg-white">
            {/* Watermark Lunas / Belum Lunas */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.07] z-0">
              {isPaidTx ? (
                <span className="text-6xl font-black tracking-widest text-emerald-600 -rotate-45 uppercase border-8 border-emerald-600 rounded-xl p-4">
                  Lunas
                </span>
              ) : (
                <span className="text-5xl font-black tracking-tight text-rose-600 -rotate-45 uppercase border-8 border-rose-600 rounded-xl p-3">
                  Belum Lunas
                </span>
              )}
            </div>

            {/* Header Toko */}
            <div className="text-center mb-4 relative z-10">
              {storeSettings?.logo && (
                <img src={storeSettings.logo} alt="Logo" className="w-16 h-16 object-contain mx-auto mb-2 grayscale" />
              )}
              <h2 className="font-bold text-base uppercase tracking-wider">{storeSettings?.storeName || 'Toko'}</h2>
              {storeSettings?.address && <p className="text-[10px] mt-1">{storeSettings.address}</p>}
              {storeSettings?.phone && <p className="text-[10px]">{storeSettings.phone}</p>}
            </div>

            <div className="border-t-[1.5px] border-dashed border-slate-300 my-3" />

            {/* Info Transaksi */}
            <div className="flex justify-between text-[10px] relative z-10">
              <span>No: {transaction.receiptNumber}</span>
              <span className="text-right">{paymentMethodName}</span>
            </div>
            <div className="flex justify-between text-[10px] mb-2 relative z-10">
              <span>{format(new Date(transaction.date), 'dd/MM/yyyy', { locale: id })}</span>
              <span>{format(new Date(transaction.date), 'HH:mm', { locale: id })}</span>
            </div>
            {transaction.customerName && (
              <div className="flex justify-between text-[10px] mb-1 relative z-10">
                <span className="text-slate-500">Pelanggan:</span>
                <span className="font-semibold uppercase truncate max-w-[150px]">{transaction.customerName}</span>
              </div>
            )}

            <div className="border-t-[1.5px] border-dashed border-slate-300 my-3" />

            {/* Daftar Item */}
            <div className="relative z-10 min-h-[80px]">
              {items.map((item, i) => (
                <div key={i} className="mb-2.5">
                  <p className="text-[11px] font-bold uppercase">{item.productName}</p>
                  {item.selectedVariants && item.selectedVariants.length > 0 && (
                    <p className="text-[9px] text-slate-500">  + {item.selectedVariants.map(v => v.optionName).join(', ')}</p>
                  )}
                  {item.notes && <p className="text-[9px] text-slate-500 italic">  Catatan: {item.notes}</p>}
                  <div className="flex justify-between text-[10px] mt-0.5">
                    <span>{item.quantity} x {rp(item.price)}</span>
                    <span className="font-medium">{rp(item.subtotal)}</span>
                  </div>
                  {(item.discountAmount ?? 0) > 0 && (
                    <div className="flex justify-between text-[10px] text-slate-500">
                      <span>  Diskon</span>
                      <span>-{rp(item.discountAmount)}</span>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="border-t-[1.5px] border-dashed border-slate-300 my-3" />

            {/* Kalkulasi Total */}
            <div className="space-y-1 text-[11px] relative z-10">
              <div className="flex justify-between">
                <span className="text-slate-600">Subtotal</span>
                <span>{rp(transaction.subtotal)}</span>
              </div>
              {txDiscountAmount > 0 && (
                <div className="flex justify-between">
                  <span className="text-slate-600">Diskon</span>
                  <span>-{rp(txDiscountAmount)}</span>
                </div>
              )}

              <div className="flex justify-between font-black text-[13px] border-t border-slate-300 pt-1.5 mt-1.5">
                <span>TOTAL</span>
                <span>{rp(transaction.total)}</span>
              </div>

              {(() => {
                const paymentsList = (transaction.payments || []) as any[];
                if (paymentsList.length > 0) {
                  return (
                    <div className="mt-2 pt-2 border-t border-slate-300">
                      <span className="text-slate-600 mb-1 block">Rincian Pembayaran:</span>
                      {paymentsList.map((p, idx) => (
                        <div key={idx} className="flex justify-between pl-2 mb-0.5">
                          <span className="text-slate-500 uppercase">{p.method_name || p.methodName || 'Pembayaran'}</span>
                          <span>{rp(p.amount)}</span>
                        </div>
                      ))}
                    </div>
                  );
                } else {
                  return (
                    <div className="flex justify-between mt-2">
                      <span className="text-slate-600">Bayar</span>
                      <span>{rp(txPaymentAmount)}</span>
                    </div>
                  );
                }
              })()}

              <div className="flex justify-between mt-1">
                <span className="text-slate-600">Kembali</span>
                <span>{rp(transaction.change)}</span>
              </div>
            </div>

            <div className="border-t-[1.5px] border-dashed border-slate-300 my-3" />

            {/* Footer */}
            <div className="text-center text-[10px] text-slate-500 relative z-10 pb-4 mt-4">
              <p>{storeSettings?.receiptFooter || 'Terima kasih atas kunjungan Anda!'}</p>
              <div className="mt-4 flex justify-center opacity-50">
                {/* Visual Barcode Placeholder */}
                <div className="w-48 h-8 flex gap-[2px] justify-center items-center">
                   {Array.from({ length: 30 }).map((_, i) => (
                     <div key={i} className="bg-slate-800 h-full" style={{ width: `${Math.random() * 3 + 1}px` }} />
                   ))}
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Tombol Aksi */}
        <div className="grid grid-cols-3 gap-3 mt-2">
          <Button 
            variant="outline" 
            className="flex flex-col items-center gap-2 h-auto py-3.5 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors rounded-xl border-slate-200 dark:border-slate-700 shadow-sm" 
            onClick={handleDownload} 
            disabled={generating || printing}
          >
            {generating ? <Loader2 className="w-5 h-5 animate-spin text-blue-500" /> : <Download className="w-5 h-5 text-slate-600 dark:text-slate-300" />}
            <span className="text-[11px] font-medium text-slate-600 dark:text-slate-300">Unduh</span>
          </Button>

          <Button 
            variant="outline" 
            className="flex flex-col items-center gap-2 h-auto py-3.5 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors rounded-xl border-slate-200 dark:border-slate-700 shadow-sm" 
            onClick={handleShare} 
            disabled={generating || printing}
          >
            {generating ? <Loader2 className="w-5 h-5 animate-spin text-blue-500" /> : <Share2 className="w-5 h-5 text-slate-600 dark:text-slate-300" />}
            <span className="text-[11px] font-medium text-slate-600 dark:text-slate-300">Bagikan</span>
          </Button>

          <Button 
            variant="outline" 
            className="flex flex-col items-center gap-2 h-auto py-3.5 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors rounded-xl border-slate-200 dark:border-slate-700 shadow-sm" 
            onClick={handleBluetoothPrint} 
            disabled={generating || printing}
          >
            {printing ? <Loader2 className="w-5 h-5 animate-spin text-blue-500" /> : <Printer className="w-5 h-5 text-slate-600 dark:text-slate-300" />}
            <span className="text-[11px] font-medium text-slate-600 dark:text-slate-300">Cetak</span>
          </Button>
        </div>

        <Button 
          variant="default" 
          className="w-full mt-4 rounded-xl py-6 font-bold shadow-md active:scale-[0.98] transition-transform" 
          onClick={onClose}
        >
          Selesai
        </Button>
      </DialogContent>
    </Dialog>
  );
}

/**
 * BankTransferModal
 * Pilih bank → Snap membuka halaman VA bank tersebut secara langsung
 * via enabled_payments — tidak melalui halaman pilihan Snap.
 */
import { useState, useCallback, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Loader2, CheckCircle2, XCircle, RefreshCw, ChevronLeft } from 'lucide-react';
import { MidtransService } from '@/services/midtransService';

interface BankTransferModalProps {
  isOpen: boolean;
  amount: number;
  customerName?: string;
  orderId?: string;
  onSuccess: () => void;
  onClose: () => void;
}

interface BankOption {
  id: string;
  name: string;
  snapKey: string; // nilai untuk enabled_payments
  color: string;
  abbr: string;
}

const BANKS: BankOption[] = [
  { id: 'bca', name: 'BCA', snapKey: 'bca_va', color: '#005CA9', abbr: 'BCA' },
  { id: 'bni', name: 'BNI', snapKey: 'bni_va', color: '#F68F1E', abbr: 'BNI' },
  { id: 'bri', name: 'BRI', snapKey: 'bri_va', color: '#004B87', abbr: 'BRI' },
  { id: 'mandiri', name: 'Mandiri', snapKey: 'mandiri_bill', color: '#003087', abbr: 'MND' },
  { id: 'seabank', name: 'SeaBank', snapKey: 'other_va', color: '#FF5722', abbr: 'SEA' },
  { id: 'permata', name: 'Permata', snapKey: 'permata_va', color: '#E30613', abbr: 'PRM' },
  { id: 'cimb', name: 'CIMB', snapKey: 'cimb_va', color: '#c0392b', abbr: 'CIMB' },
  { id: 'other', name: 'Bank Lain', snapKey: 'other_va', color: '#64748b', abbr: 'ATM' },
];

type Step = 'select' | 'loading' | 'success' | 'error';

export function BankTransferModal({
  isOpen,
  amount,
  customerName,
  onSuccess,
  onClose,
}: BankTransferModalProps) {
  const [step, setStep] = useState<Step>('select');
  const [selectedBank, setSelectedBank] = useState<BankOption | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      setStep('select');
      setSelectedBank(null);
      setErrorMsg(null);
      MidtransService.loadSnapScript().catch((e) => console.warn('Snap script:', e));
    }
  }, [isOpen]);

  const handleBankSelect = useCallback(async (bank: BankOption) => {
    setSelectedBank(bank);
    setStep('loading');
    setErrorMsg(null);
    const orderId = `MA-VA-${bank.id.toUpperCase()}-${Date.now()}`;

    try {
      const token = await MidtransService.createTransactionToken({
        transaction_details: {
          order_id: orderId,
          gross_amount: Math.round(amount),
        },
        item_details: [
          { name: 'Total Belanja MesenAe', price: Math.round(amount), quantity: 1 },
        ],
        customer_details: { first_name: customerName || 'Pelanggan MesenAe' },
        enabled_payments: [bank.snapKey],
      });

      // @ts-ignore
      if (!window.snap) throw new Error('Midtrans Snap belum siap.');

      // @ts-ignore
      window.snap.pay(token, {
        onSuccess: () => {
          setStep('success');
          setTimeout(() => onSuccess(), 1200);
        },
        onPending: () => setStep('select'),
        onError: (result: any) => {
          console.error('Snap Bank Transfer Error:', result);
          setStep('error');
          setErrorMsg('Pembayaran gagal. Silakan pilih bank lain atau coba lagi.');
        },
        onClose: () => setStep('select'),
      });

      // Set kembali ke select agar jika user tutup Snap, bisa pilih lagi
      setStep('select');
    } catch (err: any) {
      console.error('Bank Transfer Error:', err);
      setStep('error');
      setErrorMsg(err.message || `Gagal memulai transfer via ${bank.name}`);
    }
  }, [amount, customerName, onSuccess]);

  const handleClose = () => {
    if (step === 'loading') return;
    onClose();
  };

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && handleClose()}>
      <DialogContent className="max-w-[95vw] sm:max-w-sm rounded-2xl p-0 overflow-hidden z-[100]">
        {/* Header */}
        <div className="bg-gradient-to-br from-blue-600 to-blue-900 p-5 text-white">
          <DialogHeader>
            <DialogTitle className="text-white text-lg font-bold flex items-center gap-2">
              {step === 'error' && (
                <button onClick={() => setStep('select')} className="mr-1 opacity-70 hover:opacity-100">
                  <ChevronLeft className="w-5 h-5" />
                </button>
              )}
              🏦 Transfer Bank
            </DialogTitle>
            <DialogDescription className="text-white/80 text-sm mt-1">
              Pilih bank dan ikuti instruksi pembayaran
            </DialogDescription>
          </DialogHeader>
          <div className="mt-3 bg-white/20 rounded-xl p-3 text-center">
            <p className="text-xs text-white/70 font-medium">Total Transfer</p>
            <p className="text-3xl font-black text-white">Rp {amount.toLocaleString('id-ID')}</p>
            <p className="text-xs text-white/70 mt-1">{customerName || 'Pelanggan MesenAe'}</p>
          </div>
        </div>

        {/* Body */}
        <div className="p-5 overflow-y-auto max-h-[60vh] custom-scrollbar-hide">
          {step === 'select' && (
            <>
              <p className="text-sm text-muted-foreground mb-3 font-medium">Pilih bank tujuan:</p>
              <div className="grid grid-cols-4 gap-2">
                {BANKS.map((bank) => (
                  <button
                    key={bank.id}
                    onClick={() => handleBankSelect(bank)}
                    className="flex flex-col items-center justify-center p-2 rounded-xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all active:scale-95 gap-1"
                  >
                    <div
                      className="w-9 h-9 rounded-lg flex items-center justify-center text-[10px] font-black text-white bg-slate-100 overflow-hidden"
                      style={{ backgroundColor: bank.color }}
                    >
                      {['bca', 'bni', 'bri', 'mandiri', 'seabank'].includes(bank.id) ? (
                        <img src={`/ico/${bank.id}.png`} alt={bank.name} className="w-full h-full object-contain p-1 bg-white" />
                      ) : (
                        bank.abbr
                      )}
                    </div>
                    <span className="text-[10px] font-semibold text-foreground leading-tight text-center">
                      {bank.name}
                    </span>
                  </button>
                ))}
              </div>
              <Button variant="ghost" className="w-full text-muted-foreground text-sm mt-4" onClick={handleClose}>
                Batalkan
              </Button>
            </>
          )}

          {step === 'loading' && (
            <div className="flex flex-col items-center py-8 gap-3">
              <Loader2 className="w-10 h-10 text-primary animate-spin" />
              <p className="text-sm text-muted-foreground font-medium">
                Menyiapkan pembayaran via {selectedBank?.name}...
              </p>
            </div>
          )}

          {step === 'success' && (
            <div className="flex flex-col items-center py-6 gap-3">
              <div className="w-16 h-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
                <CheckCircle2 className="w-10 h-10 text-green-500" />
              </div>
              <p className="text-base font-bold text-green-600 dark:text-green-400">Transfer Berhasil!</p>
            </div>
          )}

          {step === 'error' && (
            <div className="flex flex-col items-center py-4 gap-3">
              <div className="w-14 h-14 rounded-full bg-destructive/10 flex items-center justify-center">
                <XCircle className="w-9 h-9 text-destructive" />
              </div>
              <p className="text-sm text-destructive font-medium text-center">{errorMsg}</p>
              <div className="flex gap-2 w-full">
                <Button size="sm" variant="outline" onClick={() => setStep('select')} className="flex-1 gap-1">
                  <ChevronLeft className="w-4 h-4" /> Pilih Bank Lain
                </Button>
                {selectedBank && (
                  <Button size="sm" onClick={() => handleBankSelect(selectedBank)} className="flex-1 gap-1">
                    <RefreshCw className="w-4 h-4" /> Coba Lagi
                  </Button>
                )}
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useCallback, useEffect, useRef, JSX } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
