  // ==========================================
  // States
  // ==========================================
  const [viewState, setViewState] = useState<string>(getInitialView);
  const [customerName, setCustomerName] = useState<string>(() => {
    if (typeof window !== 'undefined') return localStorage.getItem('mesenae_customerName') || '';
    return '';
  });
  const [tableNumber, setTableNumber] = useState<string>(() => {
    if (typeof window !== 'undefined') return localStorage.getItem('mesenae_tableNumber') || 'Bawa Pulang';
    return 'Bawa Pulang';
  });

  // Modals
  const [showCustomerModal, setShowCustomerModal] = useState<boolean>(false);

  // Data States
  const [cart, setCart] = useState<CartItem[]>(() => {
    if (typeof window !== 'undefined') {
      try {
        const savedCart = localStorage.getItem('mesenae_cart');
        return savedCart ? JSON.parse(savedCart) : [];
      } catch {
        return [];
      }
    }
    return [];
  });

  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedItem, setSelectedItem] = useState<MenuItem | null>(null);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window === 'undefined') return false;
    const saved = localStorage.getItem('mesenae_darkMode');
    if (saved !== null) return saved === 'true';
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  });
  const [finalOrderData, setFinalOrderData] = useState<FinalOrderData | null>(null);

  // Gunakan optional chaining atau type assertion sesuai pengembalian useDbQuery
  const storeSettingsList = (useDbQuery('storeSettings') as unknown[]) ?? [];
  const storeSettings = storeSettingsList[0] || null;

  // ==========================================
  // Custom Navigation & History Management
  // ==========================================
  const setView = useCallback((newView: string, replace: boolean = false) => {
    if (newView === viewState) return;

    if (typeof window !== 'undefined') {
      const url = new URL(window.location.href);
      url.searchParams.set('view', newView);

      if (replace) {
        window.history.replaceState({ view: newView }, '', url.toString());
      } else {
        window.history.pushState({ view: newView }, '', url.toString());
      }
    }

    setViewState(newView);
  }, [viewState]);

  // Handle PopState (Back/Forward browser/device button)
  useEffect(() => {
    if (typeof window === 'undefined') return;

    const handlePopState = (event: PopStateEvent) => {
      // Tutup modal detail menu jika sedang terbuka saat user menekan back
      if (selectedItem) {
        setSelectedItem(null);
        return;
      }
      // Tutup modal customer info jika terbuka
      if (showCustomerModal) {
        setShowCustomerModal(false);
        return;
      }

      if (event.state && event.state.view) {
        setViewState(event.state.view);
      } else {
        const params = new URLSearchParams(window.location.search);
        setViewState(params.get('view') || 'landing');
      }
    };

    window.addEventListener('popstate', handlePopState);

    // Setup initial state di history
    if (!window.history.state) {
      const url = new URL(window.location.href);
      url.searchParams.set('view', viewState);
      window.history.replaceState({ view: viewState }, '', url.toString());
    }

    return () => window.removeEventListener('popstate', handlePopState);
  }, [viewState, selectedItem, showCustomerModal]);

  // ==========================================
  // Effect Syncs
  // ==========================================
  useEffect(() => {
    if (typeof window !== 'undefined') localStorage.setItem('mesenae_customerName', customerName);
  }, [customerName]);

  useEffect(() => {
    if (typeof window !== 'undefined') localStorage.setItem('mesenae_tableNumber', tableNumber);
  }, [tableNumber]);

  useEffect(() => {
    if (typeof window !== 'undefined') localStorage.setItem('mesenae_cart', JSON.stringify(cart));
  }, [cart]);

  // Sync dark mode to document root for desktop/global styles and persist
  useEffect(() => {
    if (typeof window === 'undefined') return;
    try {
      if (isDarkMode) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      localStorage.setItem('mesenae_darkMode', String(isDarkMode));
    } catch (_) { }
  }, [isDarkMode]);

  // Handle URL Query Params for direct table scan
  useEffect(() => {
    if (typeof window === 'undefined') return;
    const params = new URLSearchParams(window.location.search);
    const table = params.get('table');

    if (table) {
      setTableNumber(table);
    }
  }, []);

  // Splash Screen & Routing Logic
  useEffect(() => {
    if (viewState === 'splash') {
      const timer = setTimeout(() => {
        if (!customerName) {
          setShowCustomerModal(true);
        }
        setView('landing', true);
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [viewState, customerName, setView]);

  // ==========================================
  // Business Logic
  // ==========================================
  const addToCart = (item: MenuItem, qty: number, notes: string, selectedVariants: Variant[]) => {
    const existingIndex = cart.findIndex((c) =>
      c.id === item.id &&
      JSON.stringify(c.selectedVariants) === JSON.stringify(selectedVariants) &&
      c.notes === notes
    );

    if (existingIndex >= 0) {
      const newCart = [...cart];
      newCart[existingIndex].qty += qty;
      setCart(newCart);
    } else {
      setCart([...cart, { ...item, cartId: Date.now(), qty, notes, selectedVariants }]);
    }
    setSelectedItem(null);
  };

  const directBuy = (item: MenuItem, qty: number, notes: string, selectedVariants: Variant[]) => {
    addToCart(item, qty, notes, selectedVariants);
    setTimeout(() => setView('cart'), 100);
  };

  const handleCustomerInfoSubmit = (name: string, table: string) => {
    setCustomerName(name);
    setTableNumber(table);
    setShowCustomerModal(false);
  };

  const updateCartQty = (cartId: number, delta: number) => {
    setCart((prevCart) => {
      const newCart = prevCart.map((item) => {
        if (item.cartId === cartId) {
          const newQty = Math.max(0, item.qty + delta);
          return { ...item, qty: newQty };
        }
        return item;
      }).filter((item) => item.qty > 0);

      if (newCart.length === 0 && viewState === 'cart') {
        setTimeout(() => setView('menu'), 0);
      }
      return newCart;
    });
  };

  const cartTotal: CartTotals = useMemo(() => {
    const subtotal = cart.reduce((sum: number, item: CartItem) => {
      const itemPrice = item.price;
      const variantsPrice = item.selectedVariants?.reduce((a: number, b: Variant) => a + b.price, 0) || 0;
      return sum + ((itemPrice + variantsPrice) * item.qty);
    }, 0);
    // Asumsi: Pajak 11%, Layanan 5% (Bisa disesuaikan dari DB)
    const tax = subtotal * 0.11;
    const service = subtotal * 0.05;
    return { subtotal, tax, service, total: subtotal + tax + service };
  }, [cart]);

  // ==========================================
  // Render
  // ==========================================
  if (!isDbConfigured) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-6 font-sans">
        <div className="max-w-md w-full bg-white rounded-[2rem] p-8 shadow-2xl shadow-slate-200/50 border border-slate-100 text-center animate-in zoom-in-95 duration-500">
          <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-600 shadow-inner">
            <Database size={32} strokeWidth={1.5} />
          </div>
          <h1 className="text-2xl font-bold text-slate-900 mb-3">Database Belum Siap</h1>
          <p className="text-sm text-slate-500 mb-6 leading-relaxed">
            Sistem tidak dapat dimuat. Pastikan Anda telah mengatur konfigurasi berikut pada Environment Variables:
          </p>
          <div className="bg-slate-50 border border-slate-100 rounded-xl p-4 text-left text-sm space-y-2.5 mb-6">
            <div className="flex items-center gap-2 text-slate-700">
              <AlertCircle size={16} className="text-amber-500" />
              <span className="font-mono font-bold text-xs">SPREADSHEET_ID</span>
            </div>
            <div className="flex items-center gap-2 text-slate-700">
              <AlertCircle size={16} className="text-amber-500" />
              <span className="font-mono font-bold text-xs">FOLDER_UTAMA_ID</span>
            </div>
          </div>
          <p className="text-[11px] text-slate-400 font-medium">
            Jika baru saja diubah, harap tunggu beberapa menit hingga proses deployment server selesai.
          </p>
        </div>
      </div>
    );
  }

  return (
    // Background utama selaras tema; darkmode diterapkan hingga ke akar
    <div className={`min-h-[100dvh] font-sans flex flex-col transition-colors duration-300 bg-slate-50 dark:bg-slate-950`}>

      {/* 
        PERUBAHAN UTAMA DESKTOP RESPONSIVE:
        1. max-w-full untuk melebar hingga memenuhi batas
        2. shadow dihilangkan pada layar besar agar menyatu seperti web profesional
        3. rounded dihilangkan sepenuhnya (border-radius = 0)
        4. margin auto agar selalu pas di tengah (jika ada pembatas) 
      */}
      <div className={`w-full max-w-[1920px] mx-auto bg-white flex-1 relative flex flex-col md:border-x border-slate-200 dark:border-slate-800 shadow-sm md:shadow-none transition-all ${isDarkMode ? 'dark customer-theme' : 'customer-theme'}`}>

        {viewState === 'splash' && <SplashScreen />}

        {viewState === 'landing' && (
          <LandingView
            setView={setView}
            customerName={customerName}
            isDarkMode={isDarkMode}
            setIsDarkMode={setIsDarkMode}
            tableNumber={tableNumber}
            setSelectedItem={setSelectedItem}
            addToCart={addToCart as any}
            cartLength={cart.length}
          />
        )}

        {viewState === 'menu' && (
          <MenuView
            setView={setView}
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            selectedCategory={selectedCategory}
            setSelectedCategory={setSelectedCategory}
            setSelectedItem={setSelectedItem}
            addToCart={addToCart as any}
            cartLength={cart.length}
          />
        )}

        {viewState === 'cart' && <CartView setView={setView} cart={cart as any} updateCartQty={updateCartQty} totals={cartTotal} setCart={setCart as any} />}
        {viewState === 'checkout' && <CheckoutView setView={setView} totals={cartTotal} cart={cart as any} customerName={customerName} setFinalOrderData={setFinalOrderData as any} setCart={setCart as any} tableNumber={tableNumber} setTableNumber={setTableNumber} />}
        {viewState === 'tracking' && <TrackingView setView={setView} finalOrderData={finalOrderData as any} tableNumber={tableNumber} storeSettings={storeSettings as any} customerName={customerName} />}
        {viewState === 'others' && <OthersView setView={setView} storeSettings={storeSettings as any} tableNumber={tableNumber} customerName={customerName} />}
        {viewState === 'history' && <HistoryView setView={setView} customerName={customerName} storeSettings={storeSettings as any} />}
        {viewState === 'success' && <SuccessView setView={setView} finalOrderData={finalOrderData as any} />}
        {viewState === 'split' && <SplitView setView={setView} cart={cart as any} totals={cartTotal} customerName={customerName} setFinalOrderData={setFinalOrderData as any} setCart={setCart as any} tableNumber={tableNumber} />}

        {/* Modal / Sheet Component */}
        {selectedItem && (
          <MenuDetailSheet
            item={selectedItem}
            onClose={() => setSelectedItem(null)}
            onAdd={addToCart}
            onDirectBuy={directBuy}
          />
        )}

        <CustomerInfoModal
          isOpen={showCustomerModal}
          onClose={() => setShowCustomerModal(false)}
          onSubmit={handleCustomerInfoSubmit}
          initialCustomerName={customerName}
          initialTableNumber={tableNumber}
        />

        {/* Floating Cart & Navigation */}
        {['menu', 'tracking', 'others', 'landing'].includes(viewState) && tableNumber && (
          <>
            {cart.length > 0 && viewState !== 'tracking' && viewState !== 'landing' && (
              <div className="fixed bottom-[88px] left-0 right-0 z-40 px-4 md:px-8 pointer-events-none flex justify-center animate-in slide-in-from-bottom-8 fade-in duration-300">
                {/* Pembungkus Cart Floating dengan lebar maksimal terkontrol agar tidak terlalu panjang di Desktop */}
                <div className="w-full max-w-md md:max-w-xl pointer-events-auto px-2">
                  <button
                    onClick={() => setView('cart')}
                    className="w-full bg-blue-600 hover:bg-blue-700 text-white p-3.5 px-5 rounded-[1.5rem] flex items-center justify-between active:scale-[0.98] transition-all border border-blue-500/50"
                  >
                    <div className="flex items-center gap-3.5">
                      <div className="relative">
                        <div className="bg-white/20 p-2.5 rounded-full backdrop-blur-md">
                          <ShoppingBag size={20} strokeWidth={2} />
                        </div>
                        <span className="absolute -top-1.5 -right-1.5 bg-rose-500 text-white text-[10px] min-w-[22px] h-[22px] px-1 flex items-center justify-center rounded-full font-black border-2 border-blue-600 shadow-sm">
                          {cart.reduce((a: number, b: CartItem) => a + b.qty, 0)}
                        </span>
                      </div>
                      <div className="text-left">
                        <p className="text-[10px] font-semibold text-blue-200 uppercase tracking-wider mb-0.5">Total Pesanan</p>
                        <p className="font-extrabold text-base leading-none">{FORMAT_IDR(cartTotal.total)}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-1 text-sm font-bold bg-white/10 px-3 py-2 rounded-xl hover:bg-white/20 transition-colors">
                      Checkout <ChevronRight size={18} strokeWidth={2.5} />
                    </div>
                  </button>
                </div>
              </div>
            )}

            <BottomNav currentView={viewState} setView={setView} />
          </>
        )}
      </div>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { X, Minus, Plus, Image as ImageIcon, CheckCircle2, Circle } from 'lucide-react';
import { FORMAT_IDR } from '@/lib/utils';
import { ProductVariantGroup } from '@/hooks/db-hooks';

interface MenuDetailSheetProps {
  item: any;
  onClose: () => void;
  onAdd: (item: any, qty: number, notes: string, variants: any[]) => void;
  onDirectBuy: (item: any, qty: number, notes: string, variants: any[]) => void;
}

export default function MenuDetailSheet({ item, onClose, onAdd, onDirectBuy }: MenuDetailSheetProps) {
  const [qty, setQty] = useState(1);
  const [notes, setNotes] = useState('');
  const [isVisible, setIsVisible] = useState(false);

  // State for selected variants: { [groupName]: { [optionName]: price } }
  const [selectedVariants, setSelectedVariants] = useState<Record<string, Record<string, number>>>({});

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300); // Tunggu animasi selesai baru unmount
  };

  const toggleVariant = (group: ProductVariantGroup, optionName: string, price: number) => {
    setSelectedVariants(prev => {
      const newSel = { ...prev };
      if (!newSel[group.name]) newSel[group.name] = {};

      if (group.type === 'single') {
        newSel[group.name] = { [optionName]: price };
      } else {
        if (newSel[group.name][optionName] !== undefined) {
          delete newSel[group.name][optionName];
        } else {
          newSel[group.name][optionName] = price;
        }
      }
      return newSel;
    });
  };

  const variantsTotal = useMemo(() => {
    let total = 0;
    for (const group in selectedVariants) {
      for (const opt in selectedVariants[group]) {
        total += selectedVariants[group][opt];
      }
    }
    return total;
  }, [selectedVariants]);

  const totalPrice = (item.price + variantsTotal) * qty;

  const getFlatSelectedVariants = () => {
    const flat: { groupName: string, optionName: string, price: number }[] = [];
    for (const groupName in selectedVariants) {
      for (const optionName in selectedVariants[groupName]) {
        flat.push({ groupName, optionName, price: selectedVariants[groupName][optionName] });
      }
    }
    return flat;
  };

  const isReady = useMemo(() => {
    if (!item.variants) return true;
    for (const group of item.variants) {
      if (group.required) {
        const selectedCount = Object.keys(selectedVariants[group.name] || {}).length;
        if (selectedCount === 0) return false;
      }
    }
    return true;
  }, [item.variants, selectedVariants]);

  const handleAdd = () => {
    if (!isReady) return;
    onAdd(item, qty, notes, getFlatSelectedVariants());
    handleClose();
  };

  const handleDirectBuy = () => {
    if (!isReady) return;
    onDirectBuy(item, qty, notes, getFlatSelectedVariants());
    handleClose();
  };

  return (
    <div className={`fixed inset-0 z-[100] flex items-end sm:items-center justify-center transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>

      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-slate-900/50 backdrop-blur-sm transition-opacity"
        onClick={handleClose}
      />

      {/* Sheet Content */}
      <div 
        className={`relative w-full max-w-md bg-white dark:bg-slate-900 sm:rounded-[2rem] rounded-t-[2rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] transform transition-transform duration-300 ease-out ${
          isVisible ? 'translate-y-0 sm:scale-100' : 'translate-y-full sm:translate-y-8 sm:scale-95'
        }`}
      >
        {/* Drag Handle (Mobile only) */}
        <div className="absolute top-0 left-0 right-0 pt-3 pb-2 flex justify-center z-20 pointer-events-none sm:hidden">
          <div className="w-12 h-1.5 bg-white/40 backdrop-blur-md rounded-full" />
        </div>

        {/* Close Button overlay */}
        <button 
          onClick={handleClose} 
          className="absolute top-4 right-4 z-20 p-2.5 bg-black/20 hover:bg-black/40 backdrop-blur-md rounded-full text-white transition-all"
          aria-label="Tutup"
        >
          <X size={20} strokeWidth={2.5} />
        </button>

        {/* Scrollable Area */}
        <div className="flex-1 overflow-y-auto pb-[140px] custom-scrollbar">

          {/* Image Section */}
          <div className="relative w-full aspect-square sm:aspect-[4/3] bg-slate-100 dark:bg-slate-800 shrink-0 flex items-center justify-center">
            {item.photo ? (
              <img src={item.photo} alt={item.name} className="w-full h-full object-cover" />
            ) : (
              <div className="flex flex-col items-center justify-center text-slate-400 gap-2">
                <ImageIcon size={48} strokeWidth={1} />
                <span className="text-sm font-medium">Belum ada foto</span>
              </div>
            )}
            <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-black/50 to-transparent pointer-events-none" />
          </div>

          {/* Details Section */}
          <div className="p-6 space-y-6">

            {/* Title & Price */}
            <div>
              <div className="flex justify-between items-start gap-4 mb-1">
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white leading-tight">
                  {item.name}
                </h2>
              </div>
              <p className="text-2xl font-extrabold text-primary mb-2">
                {FORMAT_IDR(item.price)}
              </p>
              {item.sku && (
                <p className="text-sm font-medium text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-800 inline-block px-2.5 py-1 rounded-md">
                  SKU: {item.sku}
                </p>
              )}
            </div>

            {/* Variants Section */}
            {item.variants?.length > 0 && (
              <div className="space-y-5">
                {item.variants.map((group: ProductVariantGroup, gIdx: number) => (
                  <div key={gIdx} className="bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 rounded-[1.5rem] p-5">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="font-bold text-slate-900 dark:text-white text-base">{group.name}</h3>
                        <p className="text-xs text-slate-500 mt-0.5">
                          {group.type === 'single' ? 'Pilih salah satu' : 'Bisa pilih lebih dari satu'}
                        </p>
                      </div>
                      {group.required && (
                        <span className="text-[10px] bg-rose-100 text-rose-600 dark:bg-rose-500/20 dark:text-rose-400 px-2 py-1 rounded-md font-bold uppercase tracking-wider">
                          Wajib
                        </span>
                      )}
                    </div>

                    <div className="space-y-2.5">
                      {group.options.map((opt, oIdx) => {
                        const isSelected = selectedVariants[group.name]?.[opt.name] !== undefined;
                        return (
                          <button 
                            key={oIdx} 
                            type="button"
                            onClick={() => toggleVariant(group, opt.name, opt.price)}
                            className={`w-full flex items-center justify-between p-3.5 rounded-xl border-2 transition-all ${
                              isSelected 
                                ? 'bg-primary/5 border-primary text-primary' 
                                : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 hover:border-slate-300'
                            }`}
                          >
                            <div className="flex items-center gap-3">
                              {/* Icon Checklist/Radio */}
                              {isSelected ? (
                                <CheckCircle2 className="text-primary shrink-0" size={20} />
                              ) : (
                                <Circle className="text-slate-300 dark:text-slate-600 shrink-0" size={20} />
                              )}
                              <span className={`text-sm font-semibold text-left ${isSelected ? 'text-primary' : 'text-slate-700 dark:text-slate-300'}`}>
                                {opt.name}
                              </span>
                            </div>
                            {opt.price > 0 && (
                              <span className={`text-sm font-semibold ${isSelected ? 'text-primary' : 'text-slate-500'}`}>
                                + {FORMAT_IDR(opt.price)}
                              </span>
                            )}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Notes Section */}
            <div>
              <h3 className="font-bold mb-3 text-slate-900 dark:text-white">Catatan Tambahan</h3>
              <textarea 
                placeholder="Contoh: Warna cadangan, tingkat pedas, dll..."
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-primary/50 focus:border-primary outline-none transition-all dark:text-white placeholder-slate-400"
                rows={3}
              ></textarea>
            </div>

          </div>
        </div>

        {/* Fixed Bottom Action Bar */}
        <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 px-6 py-4 z-30 shadow-[0_-10px_40px_rgba(0,0,0,0.05)]" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom) + 16px)' }}>

          <div className="flex flex-col gap-4">
            {/* Total Price & Qty Row */}
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Harga</span>
                <span className="font-bold text-xl text-slate-900 dark:text-white">
                  {FORMAT_IDR(totalPrice)}
                </span>
              </div>

              <div className="flex items-center bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-slate-200 dark:border-slate-700">
                <button 
                  onClick={() => setQty(Math.max(1, qty - 1))}
                  className="w-9 h-9 rounded-full bg-white dark:bg-slate-700 shadow-sm flex items-center justify-center text-slate-600 dark:text-slate-300 active:scale-95 transition-transform"
                >
                  <Minus size={18} strokeWidth={2.5} />
                </button>
                <span className="font-bold w-10 text-center text-slate-900 dark:text-white">{qty}</span>
                <button 
                  onClick={() => setQty(Math.min(item.stock || 99, qty + 1))} // Fallback stock
                  className="w-9 h-9 rounded-full bg-white dark:bg-slate-700 shadow-sm flex items-center justify-center text-primary active:scale-95 transition-transform"
                >
                  <Plus size={18} strokeWidth={2.5} />
                </button>
              </div>
            </div>

            {/* Action Buttons Row */}
            <div className="flex gap-3">
              <button 
                onClick={handleAdd}
                disabled={!isReady}
                className="flex-1 rounded-2xl py-3.5 font-bold text-primary bg-primary/10 hover:bg-primary/15 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                + Keranjang
              </button>
              <button 
                onClick={handleDirectBuy}
                disabled={!isReady}
                className="flex-[1.5] rounded-2xl py-3.5 font-bold text-white bg-primary hover:bg-primary/95 shadow-lg shadow-primary/30 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none"
              >
                {isReady ? 'Beli Langsung' : 'Pilih Varian Wajib'}
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

