                    {/* Badge Status */}
                    <div className="absolute top-2 left-2 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md px-2 py-1 rounded-md text-[9px] font-bold tracking-wide uppercase shadow-sm">
