              {billsRiwayat.map(bill => (
                <HistoryTicket key={bill.id} bill={bill} />
              ))}
            </div>
          )}
        </div>
      )}

      {/* Printer / Receipt Modal Khusus Dapur */}
      {receiptTx && (
        <KitchenReceiptModal
          open={!!receiptTx}
          onClose={() => setReceiptTx(null)}
          transaction={receiptTx}
          items={receiptItems || []}
          storeSettings={storeSettings}
        />
      )}
    </div>
  );
}

